double _chipHeightFor(MonthExpansionLevel level) {
  switch (level) {
    case MonthExpansionLevel.compact:
      return 36.0;
    case MonthExpansionLevel.stacked:
      return 58.0;
    case MonthExpansionLevel.details:
      return 250.0;
  }
}

double _miniHeightFor(MonthExpansionLevel level) {
  switch (level) {
    case MonthExpansionLevel.compact:
      return 0.0;
    case MonthExpansionLevel.stacked:
      return 20.0;
    case MonthExpansionLevel.details:
      return 105.0;
  }
}

List<TextSpan> _buildExternalLinkSpans(String text) {
  final spans = <TextSpan>[];
  final regex = externalLinkPattern;
  int start = 0;

  for (final match in regex.allMatches(text)) {
    if (match.start > start) {
      spans.add(TextSpan(text: text.substring(start, match.start)));
    }
    final raw = match.group(0)!;
    final url = normalizeExternalLinkToken(raw);
    if (url.isEmpty) {
      start = match.end;
      continue;
    }

    spans.add(
      TextSpan(
        text: url,
        style: const TextStyle(
          decoration: TextDecoration.underline,
          color: _blue,
        ),
        recognizer: TapGestureRecognizer()
          ..onTap = () async {
            await launchExternalTarget(url, fallbackToMaps: false);
          },
      ),
    );

    if (raw.length > url.length) {
      spans.add(TextSpan(text: raw.substring(url.length)));
    }

    start = match.end;
  }

  if (start < text.length) {
    spans.add(TextSpan(text: text.substring(start)));
  }

  return spans;
}

Future<void> _launchExternalPreviewTarget(String raw) async {
  await launchExternalTarget(raw);
}

