  /* ─────────── Ma’at Flows helpers ─────────── */

  /// True if there is at least one *active* instance of template [tplKey]
  /// with any remaining day today or in the future.
  bool _hasActiveMaatInstanceFor(String tplKey) {
    final today = DateUtils.dateOnly(DateTime.now());
    return _flows.any((f) {
      final meta = notesDecode(f.notes);
      if (meta.maatKey != tplKey || !f.active) return false;
      for (final r in f.rules) {
        if (r is _RuleDates &&
            r.dates.any((d) => !DateUtils.dateOnly(d).isBefore(today))) {
          return true;
        }
      }
      return false;
    });
  }

  /// Create a user-owned *instance* from a Ma'at template starting on [startDate].
  /// - Sequence templates use [startDate] and optionally [useKemetic].
  /// - Ongoing templates can use their own join settings, such as timezone.
  /// - Returns the created flow's id.
  Future<int> _addMaatFlowInstance({
    required _MaatFlowTemplate template,
    DateTime? startDate,
    bool useKemetic = false,
    TrackSkyTimeZone? trackSkyTimeZone,
    int alertMinutesBefore = _alertNoneMinutes,
  }) async {
    if (template.kind == _MaatFlowTemplateKind.trackSky) {
      final timezone = trackSkyTimeZone ?? detectTrackSkyTimeZone();
      final flowData = await loadTrackSkyFlowData(timezone);
      final events = upcomingTrackSkyEvents(flowData);
      if (events.isEmpty) {
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(
              content: Text('No upcoming sky events remain for this flow.'),
            ),
          );
        }
        return -1;
      }

      final dates = <DateTime>{
        for (final event in events)
          DateUtils.dateOnly(trackSkyEventStartLocal(event, timezone)),
      };
      final orderedDates = dates.toList()..sort();
      final firstG = orderedDates.first;
      final lastG = orderedDates.last;

      final flow = _Flow(
        id: -1,
        name: template.title,
        color: template.color,
        active: true,
        rules: [_RuleDates(dates: dates)],
        start: firstG,
        end: lastG,
        notes: [
          'mode=gregorian',
          'split=1',
          if (template.overview.trim().isNotEmpty)
            'ov=${Uri.encodeComponent(template.overview.trim())}',
          'maat=${template.key}',
          'sky_tz=${timezone.key}',
        ].join(';'),
      );

      final serverFlowId = await _saveNewFlow(flow);
      if (serverFlowId == null) {
        if (kDebugMode) {
          debugPrint('[trackSky] Aborting - flow insert failed');
        }
        return -1;
      }

      final repo = UserEventsRepo(Supabase.instance.client);
      for (final event in events) {
        final startLocal = trackSkyEventStartLocal(event, timezone);
        final endLocal = trackSkyEventEndLocal(event, timezone);
        final dayOnly = DateUtils.dateOnly(startLocal);
        final kyKmKd = KemeticMath.fromGregorian(dayOnly);
        final startTod = event.schedule.allDay
            ? null
            : TimeOfDay(hour: startLocal.hour, minute: startLocal.minute);
        final endTod = event.schedule.allDay
            ? null
            : TimeOfDay(hour: endLocal.hour, minute: endLocal.minute);
        final clientEventId = _buildCid(
          ky: kyKmKd.kYear,
          km: kyKmKd.kMonth,
          kd: kyKmKd.kDay,
          title: event.title,
          startHour: startTod?.hour,
          startMinute: startTod?.minute,
          allDay: event.schedule.allDay,
          flowId: serverFlowId,
        );
        final note = _Note(
          clientEventId: clientEventId,
          title: event.title,
          detail: event.detailText,
          allDay: event.schedule.allDay,
          start: startTod,
          end: endTod,
          flowId: serverFlowId,
          category: event.category,
          alertOffsetMinutes: alertMinutesBefore,
        );

        _addNote(
          kyKmKd.kYear,
          kyKmKd.kMonth,
          kyKmKd.kDay,
          event.title,
          event.detailText,
          clientEventId: clientEventId,
          allDay: event.schedule.allDay,
          start: startTod,
          end: endTod,
          flowId: serverFlowId,
          category: event.category,
          alertOffsetMinutes: alertMinutesBefore,
        );

        await _scheduleAlertForEvent(
          note: note,
          ky: kyKmKd.kYear,
          km: kyKmKd.kMonth,
          kd: kyKmKd.kDay,
          clientEventId: clientEventId,
        );

        Future.microtask(() async {
          try {
            await repo.upsertByClientId(
              clientEventId: clientEventId,
              title: event.title,
              startsAtUtc: trackSkyEventStartUtc(event, timezone),
              detail: _encodeDetailWithMeta(
                event.detailText,
                alertMinutes: alertMinutesBefore,
              ),
              location: null,
              allDay: event.schedule.allDay,
              endsAtUtc: trackSkyEventEndUtc(event, timezone),
              category: event.category,
              flowLocalId: serverFlowId,
              caller: 'track_sky_join',
            );
          } catch (_) {}
        });
      }

      setState(() {});
      return serverFlowId;
    }

    if (startDate == null) {
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('Please pick a start date first.')),
        );
      }
      return -1;
    }

    // 1) Build the 10 Gregorian dates starting at chosen start.
    final dates = <DateTime>{};
    DateTime firstG;
    if (useKemetic) {
      final k = KemeticMath.fromGregorian(startDate);
      // interpret startDate as selected Kemetic (already dateOnly)
      firstG = KemeticMath.toGregorian(k.kYear, k.kMonth, k.kDay);
    } else {
      firstG = DateUtils.dateOnly(startDate);
    }
    for (int i = 0; i < 10; i++) {
      dates.add(DateUtils.dateOnly(firstG.add(Duration(days: i))));
    }

    // 2) Build the flow object (RuleDates over those 10 days).
    final flow = _Flow(
      id: -1, // assigned on save
      name: template.title,
      color: template.color,
      active: true,
      rules: [
        _RuleDates(
          dates: dates,
          allDay: false,
          start: const TimeOfDay(hour: 9, minute: 0),
          end: const TimeOfDay(hour: 10, minute: 0),
        ),
      ],

      start: firstG,
      end: firstG.add(const Duration(days: 9)),
      // Encode meta so we can recognize in preview/end:
      // "mode=gregorian|kemetic; split=1; ov=...; maat=<key>"
      notes: [
        useKemetic ? 'mode=kemetic' : 'mode=gregorian',
        'split=1', // using explicit dates
        if (template.overview.trim().isNotEmpty)
          'ov=${Uri.encodeComponent(template.overview.trim())}',
        'maat=${template.key}',
      ].join(';'),
    );

    final serverFlowId = await _saveNewFlow(
      flow,
    ); // await save and get server ID
    if (serverFlowId == null) {
      if (kDebugMode) {
        debugPrint('[applyFlowTemplate] Aborting - flow insert failed');
      }
      return -1;
    }

    // 3) Add 10 linked notes (title + detail from template).
    // Use 9am default; users can edit/delete individual notes later if they want.
    int dayIndex = 0;
    final ordered = dates.toList()..sort();
    for (final g in ordered) {
      final kyKmKd = KemeticMath.fromGregorian(g);
      final day = template.days[dayIndex];
      for (final slot in day.notes) {
        _addNote(
          kyKmKd.kYear,
          kyKmKd.kMonth,
          kyKmKd.kDay,
          slot.title,
          slot.detail,
          allDay: false,
          start: slot.start,
          end: slot.end,
          flowId: serverFlowId,
        );
        // sync each auto-created flow day to Supabase (fire-and-forget)
        Future.microtask(() async {
          try {
            final repo = UserEventsRepo(Supabase.instance.client);
            final scheduledAt = DateTime(
              g.year,
              g.month,
              g.day,
              slot.start.hour,
              slot.start.minute,
            );
            // Use unified clientEventId for Ma'at flows as well. The note uses
            // the provided slot start/end times; flowId identifies the
            // owning flow. This allows deletion to operate uniformly.
            final String cid = _buildCid(
              ky: kyKmKd.kYear,
              km: kyKmKd.kMonth,
              kd: kyKmKd.kDay,
              title: slot.title,
              startHour: slot.start.hour,
              startMinute: slot.start.minute,
              allDay: false,
              flowId: serverFlowId,
            );
            await repo.upsertByClientId(
              clientEventId: cid,
              title: slot.title,
              startsAtUtc: scheduledAt.toUtc(),
              detail: (slot.detail ?? '').trim().isEmpty
                  ? null
                  : slot.detail!.trim(),
              location: null,
              allDay: false,
              endsAtUtc: DateTime(
                g.year,
                g.month,
                g.day,
                slot.end.hour,
                slot.end.minute,
              ).toUtc(),
              flowLocalId: serverFlowId, // attach to the flow you just created
              caller: 'maat_autoschedule',
            );
          } catch (_) {}
        });
      }

      dayIndex++;
    }
    setState(() {});
    return serverFlowId;
  }

  /// End a Ma’at flow instance:
  /// - removes any *linked* notes from today forward
  /// - sets the flow inactive
  //// === FLOW LIFECYCLE: END FLOW ===
  Future<void> _endFlow(int flowId) async {
    // ═══════════════════════════════════════════════════════════════
    // 🔧 FIXED _endFlow - Properly cleans up ALL notes (past AND future)
    // ═══════════════════════════════════════════════════════════════
    final today = DateTime.now().toUtc();
    final todayDateOnly = DateTime.utc(today.year, today.month, today.day);
    if (kDebugMode) {
      debugPrint('[endFlow] Starting cleanup for flowId=$flowId');
    }
    // 1) Remove from in-memory notes (both past AND future)
    final List<String> _keysToPrune = [];
    _notes.forEach((k, list) {
      // Remove ALL notes for this flow (not just future ones)
      final originalLength = list.length;
      list.removeWhere((n) => (n.flowId ?? -1) == flowId);
      if (kDebugMode && originalLength != list.length) {
        debugPrint(
          '[endFlow] Removed ${originalLength - list.length} notes from day $k',
        );
      }
      if (list.isEmpty) _keysToPrune.add(k);
    });
    for (final k in _keysToPrune) {
      _notes.remove(k);
    }
    // 2) Mark flow inactive in memory
    final idx = _flows.indexWhere((f) => f.id == flowId);
    if (idx >= 0) {
      final f = _flows[idx];
      _flows[idx] = _Flow(
        id: f.id,
        name: f.name,
        color: f.color,
        active: false,
        rules: f.rules,
        start: f.start,
        end: f.end,
        notes: f.notes,
        shareId: f.shareId,
        isHidden: f.isHidden, // Preserve hidden status
        isSaved: f.isSaved,
        isReminder: f.isReminder,
        reminderUuid: f.reminderUuid,
      );
    }
    if (mounted) setState(() {});
    // 3) Persist to database
    final repo = UserEventsRepo(Supabase.instance.client);
    // Mark flow as inactive
    try {
      if (idx >= 0) {
        final f = _flows[idx];
        final rulesJson = jsonEncode(f.rules.map(ruleToJson).toList());
        await repo.upsertFlow(
          id: f.id,
          name: f.name,
          color: f.color.value,
          active: false,
          startDate: f.start,
          endDate: f.end,
          notes: f.notes,
          rules: rulesJson,
          isHidden: f.isHidden,
          isSaved: f.isSaved,
          shareId: f.shareId,
          isReminder: f.isReminder,
          reminderUuid: f.reminderUuid,
        );
        if (kDebugMode) {
          debugPrint('[endFlow] ✓ Marked flow $flowId as inactive');
        }
      }
    } catch (e) {
      if (kDebugMode) {
        debugPrint('[endFlow] ⚠️ Failed to mark flow inactive: $e');
      }
    }
    // 🔧 KEY FIX: Delete ALL notes for this flow, not just future ones
    // Saved flows keep their events as templates for Flow Studio/sharing.
    final keepEvents = (idx >= 0 && _flows[idx].isSaved);
    if (!keepEvents) {
      try {
        await repo.deleteByFlowId(flowId);
        if (kDebugMode) {
          debugPrint('[endFlow] ✓ Deleted ALL notes for flowId=$flowId');
        }
      } catch (e) {
        if (kDebugMode) {
          debugPrint('[endFlow] ⚠️ Failed to delete notes: $e');
        }
      }
    } else if (kDebugMode) {
      debugPrint('[endFlow] Skipped deleting events for saved flowId=$flowId');
    }

    // Cancel all notifications for this flow's events
    try {
      final events = await repo.getAllEvents();
      for (final evt in events) {
        if (evt.flowLocalId == flowId ||
            _flowIdFromCid(evt.clientEventId ?? '') == flowId) {
          final String? cid = evt.clientEventId;
          if (cid != null) {
            try {
              await Notify.cancelNotificationForEvent(cid);
            } catch (_) {
              // ignore cancellation errors
            }
          }
        }
      }
      if (kDebugMode) {
        debugPrint('[endFlow] ✔ Cancelled notifications for flowId=$flowId');
      }
    } catch (e) {
      if (kDebugMode) {
        debugPrint('[endFlow] ⚠️ Failed to cancel notifications: $e');
      }
    }
    // Do NOT delete the flow row; keep it for Saved Flows / reactivation.
    if (kDebugMode) {
      debugPrint(
        '[endFlow] Skipping deleteFlow($flowId) — end does not delete rows',
      );
    }
    // Reload from disk to ensure UI is in sync
    await _loadFromDisk();
    if (kDebugMode) {
      debugPrint('[endFlow] ✓ Flow cleanup complete');
    }
  }
