  static const int _flowHydrationLookbackDays = 365; // 12 months back
  static const int _flowHydrationLookaheadDays = 540; // ~18 months ahead
  static const Duration _flowHydrationPadding = Duration(days: 14);

  ({DateTime startUtc, DateTime endUtc}) _computeFlowHydrationWindow(
    Set<int> activeFlowIds,
    Map<int, _Flow> flowIndex,
  ) {
    final today = DateUtils.dateOnly(DateTime.now());
    DateTime? minStart;
    DateTime? maxEnd;

    for (final fid in activeFlowIds) {
      final flow = flowIndex[fid];
      if (flow == null) continue;
      final s = flow.start != null ? DateUtils.dateOnly(flow.start!) : null;
      final e = flow.end != null ? DateUtils.dateOnly(flow.end!) : null;
      if (s != null && (minStart == null || s.isBefore(minStart))) {
        minStart = s;
      }
      if (e != null && (maxEnd == null || e.isAfter(maxEnd))) {
        maxEnd = e;
      }
    }

    final startFloor = today.subtract(
      const Duration(days: _flowHydrationLookbackDays),
    );
    DateTime start = minStart == null
        ? startFloor
        : (minStart.isBefore(startFloor) ? startFloor : minStart);

    final endCeiling = today.add(
      const Duration(days: _flowHydrationLookaheadDays),
    );
    DateTime end;
    if (maxEnd == null) {
      end = endCeiling;
    } else {
      end = maxEnd.isAfter(endCeiling) ? endCeiling : maxEnd;
    }

    start = start.subtract(_flowHydrationPadding);
    end = end.add(_flowHydrationPadding);

    final exclusiveEnd = end.add(const Duration(days: 1));
    return (startUtc: start.toUtc(), endUtc: exclusiveEnd.toUtc());
  }

  ({DateTime startUtc, DateTime endUtc}) _computeStandaloneHydrationWindow(
    List<_Flow> flows,
  ) {
    // Load a wide but bounded slice of standalone notes so we do not depend on
    // "first N" ordering. Baseline is ±_standaloneHydrationWindowYears around
    // today, widened to cover the visible flow horizon.
    final today = DateUtils.dateOnly(DateTime.now());
    final span = Duration(days: 365 * _standaloneHydrationWindowYears);

    DateTime start = today.subtract(span);
    DateTime end = today.add(span);

    for (final flow in flows) {
      final flowStart = flow.start != null
          ? DateUtils.dateOnly(flow.start!)
          : null;
      final flowEnd = flow.end != null ? DateUtils.dateOnly(flow.end!) : null;
      if (flowStart != null && flowStart.isBefore(start)) start = flowStart;
      if (flowEnd != null && flowEnd.isAfter(end)) end = flowEnd;
    }

    start = start.subtract(_standaloneHydrationPadding);
    end = end.add(_standaloneHydrationPadding);

    // Treat end as exclusive so the final day is fully included.
    final endExclusive = end.add(const Duration(days: 1));
    return (startUtc: start.toUtc(), endUtc: endExclusive.toUtc());
  }

  Future<void> _handleCreateTimedEvent(
    int ky,
    int km,
    int kd, {
    required String title,
    String? detail,
    String? location,
    required TimeOfDay start,
    required TimeOfDay end,
    bool allDay = false,
  }) async {
    try {
      await _saveSingleNoteOnly(
        selYear: ky,
        selMonth: km,
        selDay: kd,
        title: title,
        detail: detail,
        location: location,
        allDay: allDay,
        startTime: allDay ? null : start,
        endTime: allDay ? null : end,
        color: null,
      );
    } catch (e, st) {
      if (kDebugMode) {
        debugPrint('[DayView] Failed to save timed event: $e');
        debugPrint('$st');
      }
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            content: Text('Failed to save event: $e'),
            backgroundColor: Colors.red,
          ),
        );
      }
    }
  }

  Future<void> _recordEventCompletion({
