      }
    }
  }

  Future<Set<String>> _loadCompletedClientEventIds({
    int? flowId,
    DateTime? completedOnDate,
  }) async {
    final user = Supabase.instance.client.auth.currentUser;
    if (user == null) return {};
    try {
      final client = Supabase.instance.client;
      var query = client
          .from('user_event_completions')
          .select('client_event_id')
          .eq('user_id', user.id);
      if (flowId != null) {
        query = query.eq('flow_id', flowId);
      }
      if (completedOnDate != null) {
        final dateStr =
            '${completedOnDate.year}-${completedOnDate.month.toString().padLeft(2, '0')}-${completedOnDate.day.toString().padLeft(2, '0')}';
        query = query.eq('completed_on', dateStr);
      }
      final rows = await query;
      final ids = <String>{};
      for (final row in (rows as List)) {
        final cid = (row as Map<String, dynamic>)['client_event_id'] as String?;
        if (cid != null && cid.isNotEmpty) {
          ids.add(cid);
        }
      }
      return ids;
    } catch (e) {
      if (kDebugMode) {
        debugPrint('[DayView] loadCompletedClientEventIds failed: $e');
      }
      return {};
    }
  }

  void _openDaySheet(
    int kYear,
    int kMonth,
    int kDay, {
    bool allowDateChange = false,
    TimeOfDay? initialStartTime,
    TimeOfDay? initialEndTime,
    bool initialAllDay = false,
    String? initialTitle,
    String? initialLocation,
    String? initialDetail,
    Color? initialColor,
    String? initialCategory,
    int? initialAlertMinutes,
    int? editingIndex,
  }) {
    // Ensure reminder rules are loaded before building the sheet so the list is populated.
    _loadReminderRules();
    debugPrint('');
    debugPrint('┌─────────────────────────────────────┐');
    debugPrint('│ 📝 OPENING DAY SHEET                │');
    debugPrint('├─────────────────────────────────────┤');
    debugPrint('│ Date: $kYear/$kMonth/$kDay');
    debugPrint('│ allowDateChange: $allowDateChange');
    debugPrint('│ Context mounted: ${context.mounted}');
    debugPrint('│ Context widget: ${context.widget.runtimeType}');
    debugPrint('│ Build count: $_buildCount');
    debugPrint('└─────────────────────────────────────┘');
    debugPrint('');

    int selYear = kYear;
    int selMonth = kMonth;
    int selDay = kDay;

    int maxDayFor(int year, int month) =>
        (month == 13) ? (KemeticMath.isLeapKemeticYear(year) ? 6 : 5) : 30;

    final int yearStart = _today.kYear - 200;
    final int yearItem = kYear - yearStart;
    final yearCtrl = FixedExtentScrollController(
      initialItem: yearItem.clamp(0, 400).toInt(),
    );
    final monthCtrl = FixedExtentScrollController(
      initialItem: (kMonth - 1).clamp(0, 12).toInt(),
    );
    final dayCtrl = FixedExtentScrollController(initialItem: (kDay - 1));

    final rawInitialDetail = initialDetail ?? '';
    final strippedInitialDetail = _stripCidLines(rawInitialDetail);
    final initialCidMetadata = _extractCidMetadata(rawInitialDetail);

    final controllerTitle = TextEditingController(text: initialTitle ?? '');
    final controllerLocation = TextEditingController(
      text: initialLocation ?? '',
    );
    final controllerDetail = TextEditingController(text: strippedInitialDetail);

    bool allDay = initialAllDay;
    TimeOfDay? startTime =
        initialStartTime ?? const TimeOfDay(hour: 12, minute: 0);
    TimeOfDay? endTime = initialEndTime ?? const TimeOfDay(hour: 13, minute: 0);
    String? selectedCategory = initialCategory;
    int alertMinutesBefore = initialAlertMinutes ?? _alertNoneMinutes;

    // Repeat state
    NoteRepeatOption repeatOption = NoteRepeatOption.never;
    NoteRepeatEndType endType = NoteRepeatEndType.never;
    SimpleRecurrenceFrequency customFrequency = SimpleRecurrenceFrequency.daily;
    int customInterval = 1;
    DateTime? endDate;
    int endCount = 10;

    // Color state – index into _flowPalette
    int selectedColorIndex = initialColor != null
        ? _flowPalette.indexWhere((c) => c.value == initialColor.value)
        : 0;
    if (selectedColorIndex < 0) selectedColorIndex = 0;

    Map<String, dynamic> daySheetSessionPayload() {
      return <String, dynamic>{
        'kYear': selYear,
        'kMonth': selMonth,
        'kDay': selDay,
        'allowDateChange': allowDateChange,
        'title': controllerTitle.text,
        'location': controllerLocation.text,
        'detail': controllerDetail.text,
        'allDay': allDay,
        'startHour': startTime?.hour,
        'startMinute': startTime?.minute,
        'endHour': endTime?.hour,
        'endMinute': endTime?.minute,
        'colorValue': _flowPalette[selectedColorIndex].value,
        'category': selectedCategory,
        'alertMinutesBefore': alertMinutesBefore,
        'editingIndex': editingIndex,
      };
    }

    void persistDaySheetSession() {
      unawaited(
        SessionResumeService.saveResumeEntry(
          baseRoute: '/',
          kind: _kSessionResumeKindDaySheet,
          payload: daySheetSessionPayload(),
        ),
      );
    }

    controllerTitle.addListener(persistDaySheetSession);
    controllerLocation.addListener(persistDaySheetSession);
    controllerDetail.addListener(persistDaySheetSession);
    persistDaySheetSession();

    try {
      debugPrint('🚀 Attempting to show modal bottom sheet...');
      UiGuards.disableJournalSwipe();
      final tablet = _isTablet(context);
      showModalBottomSheet(
        context: context,
        isScrollControlled: true,
        backgroundColor: Colors.transparent, // ✅ More stable like Flow Studio
        useSafeArea: true,
        // iPad/tablet: allow swipe-to-close + backdrop tap to avoid trapped sheets.
        isDismissible: true,
        enableDrag: true,
        shape: const RoundedRectangleBorder(
          borderRadius: BorderRadius.vertical(top: Radius.circular(16)),
        ),
        builder: (sheetCtx) {
          final media = MediaQuery.of(sheetCtx);

          final labelStyleWhite = const TextStyle(
            color: Colors.white,
            fontSize: 18,
            fontWeight: FontWeight.w600,
          );

          final fieldLabel = const TextStyle(
            fontSize: 12,
            color: Color(0xFFBFC3C7),
          );
          bool showReminders = _noteSheetShowReminders;

          return StatefulBuilder(
            builder: (sheetCtx, setSheetState) {
              const double _detailFontSize = 12.0;
              const double _detailLineHeight = 1.35;
              const int _detailVisibleLines = 3;
              const double _detailBoxHeight =
                  _detailFontSize * _detailLineHeight * _detailVisibleLines;
              // Clamp before any toGregorian
              int dayCount = maxDayFor(selYear, selMonth);
              if (selDay > dayCount) {
                selDay = dayCount;
                if (allowDateChange && dayCtrl.hasClients) {
                  WidgetsBinding.instance.addPostFrameCallback(
                    (_) => dayCtrl.jumpToItem(selDay - 1),
                  );
                }
              }

              final titleG = KemeticMath.toGregorian(
                selYear,
                selMonth,
                selDay,
              ); // safe
              final titleText =
                  '${_monthLabel(selMonth)} $selDay • ${titleG.year}';

              final dayNotes = _getNotes(selYear, selMonth, selDay);
              final dayFlows = _getFlowOccurrences(selYear, selMonth, selDay);
              final editingBucketKey = _kKey(selYear, selMonth, selDay);
              final editingNote =
                  editingIndex != null &&
                      _notes[editingBucketKey] != null &&
                      editingIndex! < _notes[editingBucketKey]!.length
                  ? _notes[editingBucketKey]![editingIndex!]
                  : null;

              Future<void> pickStart() async {
                final t = await showTimePicker(
                  context: sheetCtx,
                  initialTime:
                      startTime ?? const TimeOfDay(hour: 12, minute: 0),
                  builder: (c, w) => Theme(
                    data: Theme.of(c).copyWith(
                      colorScheme: const ColorScheme.dark(
                        primary: _gold,
                        surface: _bg,
                        onSurface: Colors.white,
                      ),
                    ),
                    child: w ?? const SizedBox.shrink(),
                  ),
                );
                if (t == null) return;
                setSheetState(() {
                  startTime = t;
                  if (endTime != null &&
                      _toMinutes(endTime!) <= _toMinutes(t)) {
                    endTime = _addMinutes(t, 60);
                  }
                });
                persistDaySheetSession();
              }

              Future<void> pickEnd() async {
                final t = await showTimePicker(
                  context: sheetCtx,
                  initialTime:
                      endTime ??
                      (startTime != null
                          ? _addMinutes(startTime!, 60)
                          : const TimeOfDay(hour: 13, minute: 0)),
                  builder: (c, w) => Theme(
                    data: Theme.of(c).copyWith(
                      colorScheme: const ColorScheme.dark(
                        primary: _gold,
                        surface: _bg,
                        onSurface: Colors.white,
                      ),
                    ),
                    child: w ?? const SizedBox.shrink(),
                  ),
                );
                if (t == null) return;
                setSheetState(() {
                  endTime = t;
                  if (startTime != null &&
                      _toMinutes(t) <= _toMinutes(startTime!)) {
                    startTime = _addMinutes(t, -60);
                  }
                });
                persistDaySheetSession();
              }

              Widget timeButton({
                required String label,
                required TimeOfDay? value,
                required VoidCallback onTap,
                required bool enabled,
              }) {
                final text = value == null ? '--:--' : _formatTimeOfDay(value);
                return Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(label, style: fieldLabel),
                    const SizedBox(height: 6),
                    SizedBox(
                      height: 40,
                      child: OutlinedButton(
                        style: OutlinedButton.styleFrom(
                          foregroundColor: Colors.white,
                          side: const BorderSide(color: _silver, width: 1),
                        ),
                        onPressed: enabled ? onTap : null,
                        child: Text(text),
                      ),
                    ),
                  ],
                );
              }

              Widget datePicker() {
                if (!allowDateChange) {
                  return Text(titleText, style: labelStyleWhite);
                }
                return Column(
                  crossAxisAlignment: CrossAxisAlignment.stretch,
                  children: [
                    Text(
                      titleText,
                      textAlign: TextAlign.center,
                      style: labelStyleWhite,
                    ),
                    const SizedBox(height: 6),
                    SizedBox(
                      height: 128,
                      child: Row(
                        children: [
                          // Month
                          Expanded(
                            flex: 4,
                            child: CupertinoPicker(
                              scrollController: monthCtrl,
                              itemExtent: 32,
                              looping: true,
                              backgroundColor: const Color(0x00121214),
                              onSelectedItemChanged: (i) {
                                setSheetState(() {
                                  selMonth = (i % 13) + 1;
                                  final max = maxDayFor(selYear, selMonth);
                                  if (selDay > max) {
                                    selDay = max;
                                    if (dayCtrl.hasClients) {
                                      WidgetsBinding.instance
                                          .addPostFrameCallback(
                                            (_) =>
                                                dayCtrl.jumpToItem(selDay - 1),
                                          );
                                    }
                                  }
                                });
                                persistDaySheetSession();
                              },
                              children: List<Widget>.generate(13, (i) {
                                final m = i + 1;
