                                style: ElevatedButton.styleFrom(
                                  backgroundColor: _gold,
                                  foregroundColor: Colors.black,
                                ),
                                onPressed: () async {
                                  final t = controllerTitle.text.trim();
                                  final loc = controllerLocation.text.trim();
                                  final d = controllerDetail.text.trim();
                                  String detailForSave = d;
                                  if (initialCidMetadata.isNotEmpty) {
                                    if (editingIndex != null &&
                                        d == strippedInitialDetail) {
                                      // Preserve original metadata if the user didn't change the text.
                                      detailForSave = rawInitialDetail;
                                    } else {
                                      detailForSave = _appendCidMetadata(
                                        d,
                                        initialCidMetadata,
                                      );
                                    }
                                  }

                                  if (t.isEmpty) return;

                                  // Validate end time is after start time
                                  if (!allDay &&
                                      startTime != null &&
                                      endTime != null) {
                                    if (_toMinutes(endTime!) <=
                                        _toMinutes(startTime!)) {
                                      endTime = _addMinutes(startTime!, 60);
                                    }
                                  }

                                  final bool isRepeating =
                                      repeatOption != NoteRepeatOption.never;

                                  final selectedColor =
                                      _flowPalette[selectedColorIndex];

                                  final bucketKey = _kKey(
                                    selYear,
                                    selMonth,
                                    selDay,
                                  );
                                  final existingNote = editingIndex != null
                                      ? (_notes[bucketKey] != null &&
                                                editingIndex! <
                                                    _notes[bucketKey]!.length
                                            ? _notes[bucketKey]![editingIndex!]
                                            : null)
                                      : null;
                                  final existingClientEventId =
                                      existingNote?.clientEventId ??
                                      (existingNote != null &&
                                              (existingNote.flowId == null ||
                                                  existingNote.flowId == -1)
                                          ? _buildCid(
                                              ky: selYear,
                                              km: selMonth,
                                              kd: selDay,
                                              title: existingNote.title,
                                              startHour:
                                                  existingNote.start?.hour,
                                              startMinute:
                                                  existingNote.start?.minute,
                                              allDay: existingNote.allDay,
                                              flowId: -1,
                                            )
                                          : null);

                                  try {
                                    ({String clientEventId, String eventId})?
                                    saveResult;
                                    var updatedExistingStandalone = false;

                                    if (!isRepeating) {
                                      final canUpdateExisting =
                                          existingNote?.id != null &&
                                          ((existingNote?.flowId == null) ||
                                              existingNote?.flowId == -1);
                                      if (canUpdateExisting) {
                                        updatedExistingStandalone = true;
                                        saveResult =
                                            await _updateSingleNoteOnly(
                                              existingEventId:
                                                  existingNote!.id!,
                                              previousClientEventId:
                                                  existingClientEventId,
                                              selYear: selYear,
                                              selMonth: selMonth,
                                              selDay: selDay,
                                              title: t,
                                              detail: detailForSave.isEmpty
                                                  ? null
                                                  : detailForSave,
                                              location: loc.isEmpty
                                                  ? null
                                                  : loc,
                                              allDay: allDay,
                                              startTime: startTime,
                                              endTime: endTime,
                                              color: selectedColor,
                                              category: selectedCategory,
                                              alertMinutesBefore:
                                                  alertMinutesBefore,
                                            );
                                      } else {
                                        saveResult = await _saveSingleNoteOnly(
                                          selYear: selYear,
                                          selMonth: selMonth,
                                          selDay: selDay,
                                          title: t,
                                          detail: detailForSave.isEmpty
                                              ? null
                                              : detailForSave,
                                          location: loc.isEmpty ? null : loc,
                                          allDay: allDay,
                                          startTime: startTime,
                                          endTime: endTime,
                                          color: selectedColor,
                                          category: selectedCategory,
                                          alertMinutesBefore:
                                              alertMinutesBefore,
                                        );
                                      }
                                    } else {
                                      // Repeating note - create hidden flow
                                      await _saveRepeatingNoteAsHiddenFlow(
                                        selYear: selYear,
                                        selMonth: selMonth,
                                        selDay: selDay,
                                        title: t,
                                        detail: detailForSave.isEmpty
                                            ? null
                                            : detailForSave,
                                        location: loc.isEmpty ? null : loc,
                                        allDay: allDay,
                                        startTime: startTime,
                                        endTime: endTime,
                                        repeatOption: repeatOption,
                                        customFrequency: customFrequency,
                                        customInterval: customInterval,
                                        endType: endType,
                                        endDate: endDate,
                                        endCount: endCount,
                                        color: selectedColor,
                                        category: selectedCategory,
                                        alertMinutesBefore: alertMinutesBefore,
                                      );
                                    }

                                    if (editingIndex != null &&
                                        existingNote != null) {
                                      if (updatedExistingStandalone) {
                                        _removeLocalNoteOnly(
                                          selYear,
                                          selMonth,
                                          selDay,
                                          editingIndex!,
                                        );
                                      } else {
                                        final cidMatches =
                                            !isRepeating &&
                                            existingClientEventId != null &&
                                            saveResult != null &&
                                            existingClientEventId ==
                                                saveResult.clientEventId;
                                        if (cidMatches) {
                                          _removeLocalNoteOnly(
                                            selYear,
                                            selMonth,
                                            selDay,
                                            editingIndex!,
                                          );
                                        } else {
                                          await _deleteNote(
                                            selYear,
                                            selMonth,
                                            selDay,
                                            editingIndex!,
                                          );
                                        }
                                      }
                                    }
                                  } catch (e, stackTrace) {
                                    if (kDebugMode) {
                                      debugPrint(
                                        '[SaveNote] Error saving note: $e',
                                      );
                                      debugPrint(
                                        '[SaveNote] Stack trace: $stackTrace',
                                      );
                                    }
                                    if (mounted) {
                                      ScaffoldMessenger.of(
                                        context,
                                      ).showSnackBar(
                                        SnackBar(
                                          content: Text(
                                            'Failed to save note: $e',
                                          ),
                                          backgroundColor: Colors.red,
                                          duration: const Duration(seconds: 3),
                                        ),
                                      );
                                    }
                                    return; // Don't close sheet on error
                                  }

                                  if (!sheetCtx.mounted) return;
                                  Navigator.pop(sheetCtx);
                                },
                                child: const Text('Save'),
                              ),
                            ),
                          ],
                        ],
                      ),
                    ),
                  ),
                ),
              );
            },
          );
        },
      ).then((_) {
        controllerTitle.removeListener(persistDaySheetSession);
        controllerLocation.removeListener(persistDaySheetSession);
        controllerDetail.removeListener(persistDaySheetSession);
        controllerTitle.dispose();
        controllerLocation.dispose();
        controllerDetail.dispose();
        yearCtrl.dispose();
        monthCtrl.dispose();
        dayCtrl.dispose();
        unawaited(
          SessionResumeService.clearResumeEntry(
            kind: _kSessionResumeKindDaySheet,
          ),
        );
        UiGuards.enableJournalSwipe();
      });

      debugPrint('✅ Modal bottom sheet opened successfully');
    } catch (e, stackTrace) {
      debugPrint('');
      debugPrint('❌ ERROR OPENING DAY SHEET');
      debugPrint('Error: $e');
      debugPrint('Stack trace: $stackTrace');
      debugPrint('');
      controllerTitle.removeListener(persistDaySheetSession);
      controllerLocation.removeListener(persistDaySheetSession);
      controllerDetail.removeListener(persistDaySheetSession);
      controllerTitle.dispose();
      controllerLocation.dispose();
      controllerDetail.dispose();
      yearCtrl.dispose();
      monthCtrl.dispose();
      dayCtrl.dispose();
      unawaited(
        SessionResumeService.clearResumeEntry(
          kind: _kSessionResumeKindDaySheet,
        ),
      );
      UiGuards.enableJournalSwipe(); // Re-enable even on error
    }
  }

  /* ───── Natural language quick add ───── */

  DateTime _nextWeekday(DateTime base, int weekday) {
    final delta = (weekday - base.weekday + 7) % 7;
    final add = delta == 0 ? 7 : delta;
    return DateUtils.dateOnly(base.add(Duration(days: add)));
  }

  _QuickAddParse? _parseQuickAdd(String raw) {
    final input = raw.trim();
    if (input.isEmpty) return null;

    final now = DateTime.now();
    DateTime date = DateUtils.dateOnly(now);
    bool hasDate = false;
    final lower = input.toLowerCase();
    final removals = <String>[];

    // Explicit mm/dd(/yy) or m/d
    final mmdd = RegExp(
      r'(\d{1,2})/(\d{1,2})(?:/(\d{2,4}))?',
    ).firstMatch(lower);
    if (mmdd != null) {
      int m = int.parse(mmdd.group(1)!);
      int d = int.parse(mmdd.group(2)!);
      int y = mmdd.group(3) != null ? int.parse(mmdd.group(3)!) : now.year;
      if (y < 100) y += 2000;
      date = DateUtils.dateOnly(DateTime(y, m, d));
      hasDate = true;
      removals.add(mmdd.group(0)!);
    } else {
      // Month name
      final months = {
        'jan': 1,
        'january': 1,
        'feb': 2,
        'february': 2,
        'mar': 3,
        'march': 3,
        'apr': 4,
        'april': 4,
        'may': 5,
        'jun': 6,
        'june': 6,
        'jul': 7,
        'july': 7,
        'aug': 8,
        'august': 8,
        'sep': 9,
        'sept': 9,
        'september': 9,
        'oct': 10,
        'october': 10,
        'nov': 11,
        'november': 11,
        'dec': 12,
        'december': 12,
      };
      final monthMatch = RegExp(
        r'(jan|feb|mar|apr|may|jun|jul|aug|sep|sept|oct|nov|dec)[a-z]*\s+(\d{1,2})(?:,\s*(\d{2,4}))?',
      ).firstMatch(lower);
      if (monthMatch != null) {
        final m = months[monthMatch.group(1)!]!;
        final d = int.parse(monthMatch.group(2)!);
        int y = monthMatch.group(3) != null
            ? int.parse(monthMatch.group(3)!)
            : now.year;
        if (y < 100) y += 2000;
        date = DateUtils.dateOnly(DateTime(y, m, d));
        hasDate = true;
        removals.add(monthMatch.group(0)!);
      }
    }

    // Relative terms
    if (!hasDate) {
      if (lower.contains('today')) {
        date = DateUtils.dateOnly(now);
        hasDate = true;
        removals.add('today');
      } else if (lower.contains('tomorrow')) {
        date = DateUtils.dateOnly(now.add(const Duration(days: 1)));
        hasDate = true;
        removals.add('tomorrow');
      }

      final inDays = RegExp(r'in\s+(\d+)\s+day').firstMatch(lower);
      if (!hasDate && inDays != null) {
        final n = int.parse(inDays.group(1)!);
        date = DateUtils.dateOnly(now.add(Duration(days: n)));
        hasDate = true;
        removals.add(inDays.group(0)!);
      }

      // Weekday names
      if (!hasDate) {
        final weekdays = {
          'mon': DateTime.monday,
          'tue': DateTime.tuesday,
          'tues': DateTime.tuesday,
          'wed': DateTime.wednesday,
          'thu': DateTime.thursday,
          'thur': DateTime.thursday,
          'thurs': DateTime.thursday,
          'fri': DateTime.friday,
          'sat': DateTime.saturday,
          'sun': DateTime.sunday,
        };
        final wdMatch = RegExp(
          r'(next\s+)?(mon|tue|tues|wed|thu|thur|thurs|fri|sat|sun)',
        ).firstMatch(lower);
        if (wdMatch != null) {
          final wd = weekdays[wdMatch.group(2)!]!;
          date = _nextWeekday(now, wd);
          hasDate = true;
          removals.add(wdMatch.group(0)!);
        }
      }
    }

    // If explicit date is in the past, roll to next year
    if (hasDate && date.isBefore(DateUtils.dateOnly(now))) {
      date = DateUtils.dateOnly(DateTime(date.year + 1, date.month, date.day));
    }

    // Time parsing
    TimeOfDay? start;
    TimeOfDay? end;
    bool allDay = true;

    int toHour(int h, String? ap) {
      if (ap == null) return h;
      final l = ap.toLowerCase();
      if (l == 'am') {
        return h == 12 ? 0 : h;
      } else {
        return h == 12 ? 12 : h + 12;
      }
    }

    final range = RegExp(
      r'(\d{1,2})(?::(\d{2}))?\s*(am|pm)?\s*(?:-|–|to)\s*(\d{1,2})(?::(\d{2}))?\s*(am|pm)?',
      caseSensitive: false,
    ).firstMatch(lower);
    if (range != null) {
      final h1 = int.parse(range.group(1)!);
      final m1 = range.group(2) != null ? int.parse(range.group(2)!) : 0;
      final ap1 = range.group(3);
      final h2 = int.parse(range.group(4)!);
      final m2 = range.group(5) != null ? int.parse(range.group(5)!) : 0;
      final ap2 = range.group(6);
      start = TimeOfDay(hour: toHour(h1, ap1), minute: m1);
      end = TimeOfDay(hour: toHour(h2, ap2 ?? ap1), minute: m2);
      allDay = false;
      removals.add(range.group(0)!);
    } else {
      final timeMatch = RegExp(
        r'(\d{1,2})(?::(\d{2}))?\s*(am|pm)?',
        caseSensitive: false,
      ).firstMatch(lower);
      if (timeMatch != null) {
        final h = int.parse(timeMatch.group(1)!);
        final m = timeMatch.group(2) != null
            ? int.parse(timeMatch.group(2)!)
            : 0;
        final ap = timeMatch.group(3);
        start = TimeOfDay(hour: toHour(h, ap), minute: m);
        end = TimeOfDay(hour: (start.hour + 1) % 24, minute: start.minute);
        allDay = false;
        removals.add(timeMatch.group(0)!);
      }
    }

    final title = () {
      var t = input;
      for (final r in removals) {
        t = t.replaceFirst(RegExp(RegExp.escape(r), caseSensitive: false), '');
      }
      t = t.replaceAll(RegExp(r'\s+'), ' ').trim();
      return t.isEmpty ? input : t;
    }();

    return (date: date, allDay: allDay, start: start, end: end, title: title);
  }

  Future<void> _openQuickAddSheet() async {
    await showModalBottomSheet(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.black,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(16)),
      ),
      builder: (_) => _QuickAddSheet(
        parse: _parseQuickAdd,
        scaffoldMessengerContext: context,
        onSave: (parsed) async {
          final k = KemeticMath.fromGregorian(parsed.date);
          await _saveSingleNoteOnly(
            selYear: k.kYear,
            selMonth: k.kMonth,
            selDay: k.kDay,
            title: parsed.title,
            detail: null,
            location: null,
            allDay: parsed.allDay,
            startTime: parsed.allDay ? null : parsed.start,
            endTime: parsed.allDay ? null : parsed.end,
            color: null,
            alertMinutesBefore: _alertNoneMinutes,
          );
        },
        onOpenFullEditor: () {
          if (!mounted) return;
          _openDaySheet(
            _today.kYear,
            _today.kMonth,
            _today.kDay,
            allowDateChange: true,
          );
        },
      ),
    );
  }

  /* ───── UI ───── */
  bool _initOnce = false;

  /// ⚠️ ONE-TIME CACHE CLEANUP
  /// Clears stale Supabase storage and SharedPreferences cache
  /// Run once to remove "Alkaline Lunch" ghosts and ensure only true Supabase data shows
  /// Remove this method after successful cleanup
  Future<void> _performOneTimeCacheCleanup() async {
    if (kDebugMode) {
      debugPrint('🧹 [CACHE CLEANUP] Starting one-time cleanup...');
    }

    try {
      // Clear SharedPreferences (manual cache)
      final prefs = await SharedPreferences.getInstance();
      await prefs.clear();
      if (kDebugMode) {
        debugPrint('🧹 [CACHE CLEANUP] Cleared SharedPreferences');
      }

      // Sign out to force fresh session (this will also clear Supabase session cache)
      await Supabase.instance.client.auth.signOut();
      if (kDebugMode) {
        debugPrint('🧹 [CACHE CLEANUP] Signed out (app will need to re-login)');
      }

      if (kDebugMode) {
        debugPrint(
          '✅ [CACHE CLEANUP] Cleanup complete - restart app to see fresh data',
        );
      }
    } catch (e, stackTrace) {
      if (kDebugMode) {
        debugPrint('❌ [CACHE CLEANUP] Error during cleanup: $e');
        debugPrint('Stack trace: $stackTrace');
      }
    }
  }

  Future<void> _requestStartupRun({String reason = 'queued'}) async {
    final user = Supabase.instance.client.auth.currentUser;
    if (user == null) {
      _pendingInitialHydration = true;
      if (kDebugMode && kDebugStandaloneHydration) {
        debugPrint('[startup] Deferring ($reason): no authenticated user');
      }
      return;
    }
    _pendingInitialHydration = false;
    if (!mounted) return;
    _startOrCoalesceStartup(reason);
    if (_startupFlight != null && !(_startupFlight!.isCompleted)) {
      await _startupFlight!.future;
    }
  }

  void _startOrCoalesceStartup(String reason) {
    // Coalesce concurrent auth-driven runs; allow one rerun after the current flight.
    if (_startupFlight != null && !(_startupFlight!.isCompleted)) {
      _startupRerunRequested = true;
      _startupLastReason = reason;
      if (kDebugMode) {
        debugPrint('[startup] coalesce request reason=$reason');
      }
      return;
    }

    final flight = Completer<void>();
    _startupFlight = flight;
    _startupLastReason = reason;
    _startupRerunRequested = false;
    if (kDebugMode) {
      debugPrint('[startup] start reason=$reason');
    }
    () async {
      try {
        await _runStartupPipeline(reason);
      } catch (e, st) {
        debugPrint('[startup] failed: $e');
        if (kDebugMode) {
          debugPrint('$st');
        }
      } finally {
        flight.complete();
        _startupFlight = null;
        if (_startupRerunRequested) {
          final nextReason = 'rerun_after_${_startupLastReason ?? reason}';
          _startupRerunRequested = false;
          _startOrCoalesceStartup(nextReason);
        } else if (kDebugMode) {
          debugPrint('[startup] end reason=$reason');
        }
      }
    }();
  }

  @override
  void didChangeDependencies() {
    super.didChangeDependencies();

    // ✅ Subscribe to RouteObserver FIRST (before _initOnce check)
    final route = ModalRoute.of(context);
    if (route is PageRoute && !_isSubscribed) {
      routeObserver.subscribe(this, route);
      _isSubscribed = true;
    }

    // ✅ PRESERVE existing _initOnce logic
    if (!_initOnce) {
      _initOnce = true;

      // ⚠️ ONE-TIME CACHE CLEANUP
      // Set _runOneTimeCacheCleanup = true to clear stale cache, then set back to false
      if (_runOneTimeCacheCleanup) {
        _performOneTimeCacheCleanup().then((_) {
          // After cleanup, user needs to restart app to re-login
          if (kDebugMode) {
            debugPrint(
              '⚠️ [CACHE CLEANUP] App will need restart after sign-out',
            );
          }
        });
        return; // Don't load data yet - wait for restart
      }

      // 1) Load reminder rules + schedule their instances, then load flows/events
      final user = Supabase.instance.client.auth.currentUser;
      if (user != null) {
        _requestStartupRun(reason: 'init').then((_) {
          final targetFlowId = widget.initialFlowIdToEdit;
          if (!mounted) return;
          if (targetFlowId != null) {
            _openFlowEditorDirectly(targetFlowId);
          } else if (widget.openMyFlowsOnLaunch) {
            _openMyFlowsList();
          }
        });
      } else {
        _pendingInitialHydration = true;
        if (kDebugMode) {
          debugPrint(
            '[Calendar] Deferring initial hydrate until auth session is available',
          );
        }
      }
    } else if (widget.initialFlowIdToEdit != null) {
      // Already initialized (flows loaded), but widget has an initial flow id
      // e.g., if CalendarPage got rebuilt with a different target flow
      final targetFlowId = widget.initialFlowIdToEdit;
      if (targetFlowId != null) {
        _openFlowEditorDirectly(targetFlowId);
      }
    } else if (widget.openMyFlowsOnLaunch) {
      // If already initialized and caller requested My Flows, honor it.
      WidgetsBinding.instance.addPostFrameCallback((_) {
        if (mounted) _openMyFlowsList();
      });
    }

    if (_pendingInitialHydration &&
        Supabase.instance.client.auth.currentUser != null) {
      _requestStartupRun(reason: 'init-pending');
    }
  }

  Future<void> _runStartupPipeline(String reason) async {
    final user = Supabase.instance.client.auth.currentUser;
    if (user == null) {
      if (kDebugMode) {
        debugPrint('[startup] abort: no authenticated user reason=$reason');
      }
      return;
    }
    try {
      await ShareRepo(
        Supabase.instance.client,
      ).syncAcceptedInviteCalendarImports();
    } catch (e, st) {
      if (kDebugMode) {
        debugPrint('[startup] invite import sync failed: $e');
        debugPrint('$st');
      }
    }
    // Order: load reminder rules, hydrate events/flows, then sync reminders in background.
    await _loadReminderRules();
    await _loadFromDisk(source: 'startup:$reason');
    await _maybeLoadDecanReflectionPrompt();
    unawaited(() async {
      try {
        await _syncReminderEvents(refreshUi: false);
      } catch (e, st) {
        if (kDebugMode) {
          debugPrint('[startup] reminder sync failed (async): $e');
          debugPrint('$st');
        }
      }
    }());
  }

  Future<void> _loadFromDisk({String source = 'manual'}) async {
    if (_isLoadingFromDisk) {
      if (kDebugMode && kDebugStandaloneHydration) {
        debugPrint(
          '[loadFromDisk] Skipping duplicate load (in flight) source=$source',
        );
      }
      return;
    }
    _isLoadingFromDisk = true;

    print('=== _loadFromDisk START ($source) ===');

    final currentUser = Supabase.instance.client.auth.currentUser;
    if (currentUser == null) {
      if (kDebugMode) {
        debugPrint('[loadFromDisk] Skipping load: no authenticated user');
      }
      _isLoadingFromDisk = false;
      return;
    }
    await _ensureManualDeleteTombstonesLoaded();
    if (kDebugMode && kDebugStandaloneHydration) {
      final uid = currentUser.id;
      final truncated = uid.length > 8 ? '${uid.substring(0, 8)}...' : uid;
      debugPrint('[loadFromDisk] Authenticated as $truncated source=$source');
    }

    try {
      // Ensure reminder rules are loaded before hydrating events so we can filter orphaned reminder instances.
      await _loadReminderRules();

      final repo = UserEventsRepo(Supabase.instance.client);
      final currentUser = Supabase.instance.client.auth.currentUser;

      // Flow-first: load flows, then events; join only to known active flows
      final List<_Flow> newFlows = [];
      final Map<String, List<_Note>> newNotes = {};
      int nextFlowId = _nextFlowId;

      // Load flows into _flows list
      final serverFlows = await repo.getAllFlows();
      if (kDebugMode) {
        debugPrint('[loadFromDisk] getAllFlows count: ${serverFlows.length}');
      }
      for (final f in serverFlows) {
        final repMeta = _decodeRepeatingNoteMetadata(f.notes);
        final derivedHidden =
            f.isHidden ||
            repMeta.detail != null ||
            repMeta.location != null ||
            repMeta.category != null;
        if (kDebugMode && derivedHidden) {
          final fromDb = f.isHidden;
          final fromRepMeta =
              repMeta.detail != null ||
              repMeta.location != null ||
              repMeta.category != null;
          debugPrint(
            '[loadFromDisk] hidden flow id=${f.id} name="${f.name}" fromDb=$fromDb fromRepMeta=$fromRepMeta',
          );
        }
        final flow = _Flow(
          id: f.id,
          name: f.name,
          color: Color(rgbToArgb(f.color)),
          active: f.active,
          isSaved: f.isSaved,
          rules: _parseRules(f.rules),
          start: f.startDate,
          end: f.endDate,
          notes: f.notes,
          shareId: f.shareId, // NEW: Load share_id
          isHidden: derivedHidden,
          isReminder: f.isReminder,
          reminderUuid: f.reminderUuid,
        );
        newFlows.add(flow);
        // 🔍 DEBUG: Log what color came from database for ALL custom flows
        // Log flows with ID greater than 156 to catch all user-created flows
        if (kDebugMode && f.id > 156) {
          debugPrint(
            '[loadFlows] Flow ${f.id} "${f.name}" loaded with color=${f.color} (0x${f.color.toRadixString(16)})',
          );
        }
        if (flow.id >= nextFlowId) nextFlowId = flow.id + 1;
      }

      // Ensure reminder rules are present from loaded reminder flows if they didn't load earlier.
      // (Run after commit to use new flow state.)
      if (kDebugMode) {
        final hiddenCount = newFlows.where((f) => f.isHidden).length;
        final activeCount = newFlows.where((f) => f.active).length;
        final expiredCount = newFlows
            .where((f) => !_isActiveByEndDate(f.end))
            .length;
        debugPrint(
          '[loadFromDisk] newFlows: total=${newFlows.length} hidden=$hiddenCount active=$activeCount expired=$expiredCount',
        );
      }

      // Build index/maps for later use
      final Map<int, _Flow> flowIndex = {for (final f in newFlows) f.id: f};

      // Hydrate events for flows that are still active and in-range.
      // Hidden flows (repeating notes) must be included so their occurrences appear.
      final hydrationFlowIds = newFlows
          .where((f) => f.active && _isActiveByEndDate(f.end))
          .map((f) => f.id)
          .toSet(); // 👈 Set for O(1) contains() lookups
      if (kDebugMode) {
        debugPrint(
          '[loadFromDisk] hydrationFlowIds count: ${hydrationFlowIds.length}',
        );
        if (hydrationFlowIds.isNotEmpty) {
          for (final fid in hydrationFlowIds) {
            final flow = flowIndex[fid];
            if (flow == null) continue;
            final rn = _decodeRepeatingNoteMetadata(flow.notes);
            final looksLikeRepeatingNote =
                rn.detail != null || rn.location != null || rn.category != null;
            debugPrint(
              '[loadFromDisk] flow id=$fid name="${flow.name}" '
              'isReminder=${flow.isReminder} hidden=${flow.isHidden} '
              'notesLikeRepeatingNote=$looksLikeRepeatingNote',
            );
          }
        }
      }

      ({DateTime startUtc, DateTime endUtc})? flowWindow;
      if (hydrationFlowIds.isNotEmpty) {
        flowWindow = _computeFlowHydrationWindow(hydrationFlowIds, flowIndex);
        if (kDebugMode) {
          debugPrint(
            '[loadFromDisk] flow hydration window '
            '${flowWindow.startUtc.toIso8601String()} → ${flowWindow.endUtc.toIso8601String()}',
          );
        }
      }

      // Batched fetch of flow-backed events to avoid N sequential network calls.
      final Map<int, List<FlowEventRow>> eventsByFlowId = {};
      if (hydrationFlowIds.isNotEmpty) {
        try {
          final batchedEvents = await repo.getEventsForFlowIds(
            hydrationFlowIds,
            startUtc: flowWindow?.startUtc,
            endUtc: flowWindow?.endUtc,
          );
          for (final evt in batchedEvents) {
            final fid = evt.flowLocalId;
            if (fid == null) continue;
            if (!hydrationFlowIds.contains(fid)) continue;
            eventsByFlowId.putIfAbsent(fid, () => <FlowEventRow>[]).add(evt);
          }
          if (kDebugMode) {
            debugPrint(
              '[loadFromDisk] getEventsForFlowIds count=${batchedEvents.length} flows=${eventsByFlowId.length}',
            );
          }
        } catch (err, st) {
          if (kDebugMode) {
            debugPrint('[loadFromDisk] batched flow event fetch failed: $err');
            debugPrint('$st');
          }
        }
      }

      // Fallback to per-flow fetch if batching fails or returns nothing.
      if (eventsByFlowId.isEmpty && hydrationFlowIds.isNotEmpty) {
        for (final flowId in hydrationFlowIds) {
          try {
            final flowEvents = await repo.getEventsForFlow(
              flowId,
              startUtc: flowWindow?.startUtc,
              endUtc: flowWindow?.endUtc,
            );
            eventsByFlowId[flowId] = flowEvents;
            if (kDebugMode) {
              debugPrint(
                '[loadFromDisk] getEventsForFlow($flowId) count: ${flowEvents.length} (fallback)',
              );
            }
          } catch (err, st) {
            if (kDebugMode) {
              debugPrint(
                '[loadFromDisk] failed to hydrate events for flow $flowId: $err',
              );
              debugPrint('$st');
            }
          }
        }
      } else if (kDebugMode && eventsByFlowId.isNotEmpty) {
        eventsByFlowId.forEach((fid, events) {
          debugPrint(
            '[loadFromDisk] flow $fid events (batched) count: ${events.length}',
          );
        });
      }

      int flowAddedCount = 0;

      for (final flowId in hydrationFlowIds) {
        try {
          final flowEvents = eventsByFlowId[flowId] ?? const <FlowEventRow>[];

          for (final evt in flowEvents) {
            // Convert DB UTC timestamps -> device local -> Kemetic date
            final localStart = evt.startsAtUtc.toLocal();

            final kDate = KemeticMath.fromGregorian(localStart);

            // Build _Note, same shape the rest of the app expects
            // 👈 SAFETY NET: Skip events for flows that don't exist or are inactive/expired.
            final owningFlow = flowIndex[flowId];
            final flowEligible =
                owningFlow != null &&
                owningFlow.active &&
                _isActiveByEndDate(owningFlow.end);
            if (!flowEligible) {
              // skip events that belong to deleted / inactive / expired flows
              continue;
            }

            final startTime = evt.allDay
                ? null
                : TimeOfDay.fromDateTime(localStart);
            final endTime = evt.endsAtUtc == null
                ? null
                : TimeOfDay.fromDateTime(evt.endsAtUtc!.toLocal());
            if ((evt.category ?? '') == 'tombstone') {
              continue;
            }

            final meta = _decodeDetailMetadata(evt.detail);
            final cleanedDetail = _cleanDetail(meta.detail);

            if (_isTombstoned(evt.clientEventId)) {
              continue;
            }
            if (_isPendingDelete(
              id: evt.id,
              clientEventId: evt.clientEventId,
              kYear: kDate.kYear,
              kMonth: kDate.kMonth,
              kDay: kDate.kDay,
              title: evt.title,
              allDay: evt.allDay,
              start: startTime,
              end: endTime,
              flowId: flowId,
            )) {
              continue;
            }

            final note = _Note(
              id: evt.id,
              clientEventId: evt.clientEventId,
              title: _cleanTitle(evt.title),
              detail: cleanedDetail, // Clean the flowLocalId prefix
              location: evt.location,
              allDay: evt.allDay,
              start: startTime,
              end: endTime,
              flowId: flowId,
              category: evt.category,
              isReminder: owningFlow?.isReminder ?? false,
              reminderId: (owningFlow?.isReminder ?? false)
                  ? owningFlow?.reminderUuid
                  : null,
              manualColor: meta.color,
              alertOffsetMinutes: meta.alertMinutes,
            );

            final key = _kKey(kDate.kYear, kDate.kMonth, kDate.kDay);
            final bucket = newNotes.putIfAbsent(key, () => <_Note>[]);

            // Dedup (title + start time match) so we don't spam UI
            final already = bucket.any(
              (n) =>
                  n.flowId == note.flowId &&
                  n.start?.hour == note.start?.hour &&
                  n.start?.minute == note.start?.minute,
            );

            if (!already) {
              bucket.add(note);
              flowAddedCount++;
            }
          }
        } catch (err, st) {
          if (kDebugMode) {
            debugPrint(
              '[loadFromDisk] failed to hydrate events for flow $flowId: $err',
            );
            debugPrint('$st');
          }
        }
      }

      if (kDebugMode) {
        debugPrint(
          '[loadFromDisk] flow notes added to newNotes: $flowAddedCount',
        );
      }

      // Load standalone events (single notes with flow_local_id = null)
      // 🚫 HARD GUARDS prevent old/zombie flow events from loading
      try {
        final standaloneWindow = _computeStandaloneHydrationWindow(newFlows);
        final standaloneResult = await repo.getStandaloneEventsForDateRangeAll(
          startUtc: standaloneWindow.startUtc,
          endUtc: standaloneWindow.endUtc,
          pageSize: 1000,
        );
        final standaloneEvents = standaloneResult.events;

        if (kDebugMode && kDebugStandaloneHydration) {
          final uid = currentUser?.id ?? 'nouser';
          final truncated = uid.length > 8 ? '${uid.substring(0, 8)}...' : uid;
          debugPrint(
            '[_loadFromDisk] standalone events fetched=${standaloneEvents.length} '
            'pages=${standaloneResult.pageCount} raw=${standaloneResult.rawCount} '
            'window=${standaloneWindow.startUtc.toIso8601String()} → ${standaloneWindow.endUtc.toIso8601String()} '
            'user=$truncated',
          );
          if (standaloneEvents.isEmpty) {
            debugPrint(
              '[_loadFromDisk] ⚠️ No standalone events returned; check RLS/query and Supabase logs',
            );
          }
        }

        int standaloneAddedCount = 0;

        for (final evt in standaloneEvents) {
          try {
            final cid = evt.clientEventId ?? '';
            final rawDetail = evt.detail ?? '';

            // 🚫 HARD GUARD 1: Any event with a flowLocalId is NOT standalone
            if (evt.flowLocalId != null) {
              continue;
            }

            // 🚫 HARD GUARD 2: Legacy flow copies where detail starts with "flowLocalId="
            if (rawDetail.startsWith('flowLocalId=')) {
              continue;
            }

            // 🚫 HARD GUARD 3: Legacy Ma'at events using "maat:" prefix
            if (cid.startsWith('maat:')) {
              continue;
            }

            // 🚫 HARD GUARD 4a: Unified CID events (ky=...|f=123) referencing flows.
            // If f != -1 AND evt.flowLocalId == null → orphaned zombie.
            if (cid.contains('|f=')) {
              final match = RegExp(r'\|f=([\-0-9]+)').firstMatch(cid);
              if (match != null) {
                final fVal = int.tryParse(match.group(1) ?? '-1') ?? -1;
                if (fVal != -1) {
                  continue;
                }
              }
            }

            // 🚫 HARD GUARD 4b: Reminder instances whose rule no longer exists (or was ended/deleted).
            if (cid.startsWith('reminder:')) {
              final rid = _reminderRuleIdFromCid(cid);
              final exists =
                  rid != null && _reminderRules.any((r) => r.id == rid);
              final ended = rid != null && _endedReminderIds.contains(rid);
              if (!exists || ended) {
                continue;
              }
            }

            // ✅ Nutrition: treat as reminder if a matching rule exists
            bool isReminderEvent = cid.startsWith('reminder:');
            String? reminderRuleId = _reminderRuleIdFromCid(cid);
            if (cid.startsWith('nutrition:')) {
              final parts = cid.split(':');
              if (parts.length >= 3) {
                final itemId = parts.sublist(1, parts.length - 1).join(':');
                final rid = 'nutrition:$itemId';
                final exists =
                    _reminderRules.any((r) => r.id == rid) &&
                    !_endedReminderIds.contains(rid);
                if (exists) {
                  isReminderEvent = true;
                  reminderRuleId = rid;
                }
              }
            }

            // ✅ If it passed all guards → this is a true standalone note
            final localStart = evt.startsAtUtc.toLocal();
            final kDate = KemeticMath.fromGregorian(localStart);
            final decoded = _decodeDetailMetadata(rawDetail);
            final cleanedDetail = _cleanDetail(decoded.detail);

            final startTime = evt.allDay
                ? null
                : TimeOfDay.fromDateTime(localStart);
            final endTime = evt.endsAtUtc == null
                ? null
                : TimeOfDay.fromDateTime(evt.endsAtUtc!.toLocal());
            if ((evt.category ?? '') == 'tombstone') {
              continue;
            }

            if (_isTombstoned(evt.clientEventId)) {
              continue;
            }
            if (_isPendingDelete(
              id: evt.id,
              clientEventId: evt.clientEventId,
              kYear: kDate.kYear,
              kMonth: kDate.kMonth,
              kDay: kDate.kDay,
              title: evt.title,
              allDay: evt.allDay,
              start: startTime,
              end: endTime,
              flowId: -1,
            )) {
              continue;
            }

            final note = _Note(
              id: evt.id,
              clientEventId: evt.clientEventId,
              title: _cleanTitle(evt.title),
              detail: cleanedDetail,
              location: evt.location,
              allDay: evt.allDay,
              start: startTime,
              end: endTime,
              flowId: -1, // Standalone notes have flowId = -1
              manualColor: decoded.color,
              category: evt.category,
              isReminder: isReminderEvent,
              reminderId: reminderRuleId,
              alertOffsetMinutes: decoded.alertMinutes,
            );

            final key = _kKey(kDate.kYear, kDate.kMonth, kDate.kDay);
            final bucket = newNotes.putIfAbsent(key, () => <_Note>[]);

            bool skip = false;
            int? replaceIndex;
            final incomingKey = _standaloneDedupeKey(note);
            final incomingPriority = _standalonePriority(note.clientEventId);

            for (int i = 0; i < bucket.length; i++) {
              final existing = bucket[i];
              if ((existing.flowId ?? -1) != -1) continue; // skip flow-driven

              if (existing.clientEventId != null &&
                  note.clientEventId != null &&
                  existing.clientEventId == note.clientEventId) {
                skip = true;
                if (kDebugMode && kDebugStandaloneHydration) {
                  debugPrint(
                    '[_loadFromDisk] dedupe by clientEventId ${note.clientEventId} in $key',
                  );
                }
                break;
              }

              if (existing.isReminder || note.isReminder) {
                if (existing.isReminder &&
                    note.isReminder &&
                    existing.reminderId == note.reminderId &&
                    existing.start?.hour == note.start?.hour &&
                    existing.start?.minute == note.start?.minute) {
                  skip = true;
                  if (kDebugMode && kDebugStandaloneHydration) {
                    debugPrint(
                      '[_loadFromDisk] dedupe reminder in $key ${note.reminderId}',
                    );
                  }
                  break;
                }
                continue;
              }

              final existingKey = _standaloneDedupeKey(existing);
              if (existingKey == incomingKey) {
                final existingPriority = _standalonePriority(
                  existing.clientEventId,
                );
                if (incomingPriority > existingPriority) {
                  replaceIndex = i;
                } else {
                  skip = true;
                }
                if (kDebugMode && kDebugStandaloneHydration) {
                  debugPrint(
                    '[_loadFromDisk] dedupe key match in $key keep=${replaceIndex != null ? 'incoming' : 'existing'} '
                    'incomingCid=${note.clientEventId} existingCid=${existing.clientEventId}',
                  );
                }
                break;
              }
            }

            if (skip) {
              continue;
            }

            if (replaceIndex != null) {
              bucket[replaceIndex] = note;
              if (kDebugMode && kDebugStandaloneHydration) {
                debugPrint(
                  '[_loadFromDisk] replaced duplicate standalone with cid=${note.clientEventId} key=$key',
                );
              }
            } else {
              bucket.add(note);
              standaloneAddedCount++; // ✅ important: track how many actually added
              if (kDebugMode && kDebugStandaloneHydration) {
                debugPrint(
                  '[_loadFromDisk] added standalone id=${evt.id} cid=${note.clientEventId ?? ''} '
                  'key=$key start=${note.start == null ? 'all-day' : _formatTimeOfDay(note.start!)}',
                );
              }
            }
          } catch (rowErr, rowSt) {
            debugPrint(
              '[_loadFromDisk] ⚠️ standalone row skipped: $rowErr (id=${evt.id} cid=${evt.clientEventId})',
            );
            if (kDebugMode && kDebugStandaloneHydration) {
              debugPrint('$rowSt');
            }
            continue;
          }
        }

        if (kDebugMode) {
          debugPrint(
            '[_loadFromDisk] loaded $standaloneAddedCount standalone events after filtering '
            '(${standaloneWindow.startUtc.toIso8601String()} → ${standaloneWindow.endUtc.toIso8601String()})',
          );
        }
      } catch (err, st) {
        if (kDebugMode) {
          debugPrint('[loadFromDisk] failed to load standalone events: $err');
          debugPrint('$st');
        }
      }

      // force rebuild
      _flows
        ..clear()
        ..addAll(newFlows);
      _notes
        ..clear()
        ..addAll(newNotes);
      if (kDebugMode && kDebugStandaloneHydration) {
        final totalNotes = newNotes.values.fold<int>(
          0,
          (sum, list) => sum + list.length,
        );
        debugPrint(
          '[_loadFromDisk] committed _notes keys=${newNotes.length} totalNotes=$totalNotes',
        );
        for (final key in _debugStandaloneKeys) {
          final bucket = newNotes[key];
          if (bucket != null) {
            debugPrint(
              '[_loadFromDisk] bucket $key titles=${bucket.map((n) => n.title).join(' | ')}',
            );
          } else {
            debugPrint('[_loadFromDisk] bucket $key empty');
          }
        }
      }
      _nextFlowId = nextFlowId;

      if (kDebugMode) {
        debugPrint(
          '[loadFromDisk] committed _flows.length=${_flows.length} _notes keys=${_notes.length}',
        );
      }

      _rebuildReminderRulesFromFlowsIfMissing();

      setState(() {});
      _bumpDataVersion();
      await _regenReminderNotes();
    } catch (e, stackTrace) {
      print('Supabase sync FAILED: $e');
      print('Stack: $stackTrace');
    } finally {
      _isLoadingFromDisk = false;
    }

    print('=== _loadFromDisk END ($source) ===');
  }

  /// Allows other screens (e.g., Settings) to trigger a fresh sync of flows/notes.
  Future<void> reloadFromOutside() => _refreshAfterReturn();

  static Map<String, dynamic> ruleToJson(FlowRule r) {
    if (r is _RuleWeek) {
      return {
        'type': 'week',
        'weekdays': r.weekdays.toList(),
        'allDay': r.allDay,
        if (r.start != null) 'startHour': r.start!.hour,
        if (r.start != null) 'startMinute': r.start!.minute,
        if (r.end != null) 'endHour': r.end!.hour,
        if (r.end != null) 'endMinute': r.end!.minute,
      };
    }
    if (r is _RuleDecan) {
      return {
        'type': 'decan',
        'months': r.months.toList(),
        'decans': r.decans.toList(),
        'daysInDecan': r.daysInDecan.toList(),
        'allDay': r.allDay,
        if (r.start != null) 'startHour': r.start!.hour,
        if (r.start != null) 'startMinute': r.start!.minute,
        if (r.end != null) 'endHour': r.end!.hour,
        if (r.end != null) 'endMinute': r.end!.minute,
      };
    }
    if (r is _RuleDates) {
      return {
        'type': 'dates',
        'dates': r.dates.map((d) => d.millisecondsSinceEpoch).toList(),
        'allDay': r.allDay,
        if (r.start != null) 'startHour': r.start!.hour,
        if (r.start != null) 'startMinute': r.start!.minute,
        if (r.end != null) 'endHour': r.end!.hour,
        if (r.end != null) 'endMinute': r.end!.minute,
      };
    }
    throw ArgumentError('Unknown rule type');
  }

  List<FlowRule> _parseRules(String rulesJson) {
    if (rulesJson.isEmpty) return [];
    try {
      final parsed = jsonDecode(rulesJson) as List;
      return parsed
          .map((j) => CalendarPage.ruleFromJson(j as Map<String, dynamic>))
          .toList();
    } catch (_) {
      return [];
    }
  }

  List<FlowRule> _rulesFromReminder(ReminderRule rule) {
    // We rely on reminder recurrence engine; leave flow rules empty.
    return const [];
  }

  Future<int?> _findFlowIdByReminderUuid(String reminderUuid) async {
    final dbUuid = _dbReminderUuidFromRuleId(reminderUuid);
    if (dbUuid == null) return null;
    try {
      final repo = FlowsRepo(Supabase.instance.client);
      return await repo.getFlowIdByReminderUuid(dbUuid);
    } catch (_) {
      return null;
    }
  }

  bool _rulesEqual(List<dynamic> oldRulesJson, List<FlowRule> newRules) {
    if (oldRulesJson.length != newRules.length) return false;
    List<Map<String, dynamic>> _normalize(List<Map<String, dynamic>> list) {
      list.sort(
        (a, b) =>
            (a['type'] as String? ?? '').compareTo(b['type'] as String? ?? ''),
      );
      return list;
    }

    final oldNormalized = _normalize(
      oldRulesJson.map((r) => Map<String, dynamic>.from(r as Map)).toList(),
    );
    final newNormalized = _normalize(
      newRules
          .map(ruleToJson)
          .map((r) => Map<String, dynamic>.from(r))
          .toList(),
    );
    return jsonEncode(oldNormalized) == jsonEncode(newNormalized);
  }

  bool _isColorOnlyChange(FlowRow oldFlow, _Flow newFlow) {
    if (oldFlow.name != newFlow.name) return false;
    if (oldFlow.notes != newFlow.notes) return false;
    if (oldFlow.startDate != newFlow.start) return false;
    if (oldFlow.endDate != newFlow.end) return false;
    if (!_rulesEqual(oldFlow.rules, newFlow.rules)) return false;
    return oldFlow.color != newFlow.color.value;
  }

  Future<void> _scheduleAlertForEvent({
    required _Note note,
    required int ky,
    required int km,
    required int kd,
    required String clientEventId,
    String? eventId,
  }) async {
    if (note.alertOffsetMinutes == _alertNoneMinutes) {
      try {
        await Notify.cancelNotificationForEvent(clientEventId);
      } catch (_) {
        // Ignore cancellation failures; nothing else to do.
      }
      return;
    }

    final alertAtLocal = _alertDateTimeLocal(
      note: note,
      kYear: ky,
      kMonth: km,
      kDay: kd,
    );
    final effectiveMinutes = _effectiveAlertMinutes(note.alertOffsetMinutes);
    if (alertAtLocal == null || effectiveMinutes == null) return;

    final cleanedDetail = _cleanDetail(note.detail);
    final bodyLines = <String>[
      if ((note.location ?? '').trim().isNotEmpty) note.location!.trim(),
      if (cleanedDetail.isNotEmpty) cleanedDetail,
    ];
    final body = bodyLines.isEmpty ? null : bodyLines.join('\n');

    await Notify.scheduleAlertWithPersistence(
      clientEventId: clientEventId,
      scheduledAt: alertAtLocal,
      title: note.title,
      body: body,
      payload: '{}',
    );

    final reminderId = _reminderIdForNote(note, alertAtLocal.toUtc());
    await _reminderService.addOrUpdate(
      Reminder(
        id: reminderId,
        eventId: eventId,
        title: note.title,
        detail: cleanedDetail.isEmpty ? null : cleanedDetail,
        alertAtUtc: alertAtLocal.toUtc(),
        flowId: note.flowId?.toString(),
        createdAt: DateTime.now().toUtc(),
        updatedAt: DateTime.now().toUtc(),
      ),
    );
  }

  // Persist flows + planned notes coming back from Flow Studio
  // AFTER
  Future<int?> _persistFlowStudioResult(_FlowStudioResult r) async {
    final repo = UserEventsRepo(Supabase.instance.client);

    // 1) Deletes take precedence
    final deleteId = r.deleteFlowId;
    if (deleteId != null) {
      if (kDebugMode) {
        debugPrint('[persistFlowStudio] Deleting flowId=$deleteId');
      }
      // 🔧 KEY FIX: Delete ALL notes for this flow (not just future ones)
      try {
        await repo.deleteByFlowId(deleteId);
        if (kDebugMode) {
          debugPrint('[persistFlowStudio] ✓ Deleted ALL notes for flow');
        }
      } catch (e) {
        if (kDebugMode) {
          debugPrint('[persistFlowStudio] ⚠️ Failed to delete notes: $e');
        }
        rethrow; // bubble up so we don't silently keep the flow
      }
      try {
        await repo.deleteFlow(deleteId);
        if (kDebugMode) {
          debugPrint('[persistFlowStudio] ✓ Deleted flow from database');
        }
      } catch (e) {
        if (kDebugMode) {
          debugPrint('[persistFlowStudio] ⚠️ Failed to delete flow: $e');
        }
        rethrow; // bubble up and avoid thinking it was removed
      }
      // Remove the flow from memory
      _flows.removeWhere((f) => f.id == deleteId);
      setState(() {});
      _notifyDayViewDataChanged();
      if (kDebugMode) {
        debugPrint('[persistFlowStudio] ✓ Flow deletion complete');
      }
      return deleteId;
    }

    // 2) Save/create flow if provided
    _Flow? saved;
    FlowRow? oldFlowRow;
    if (r.savedFlow != null) {
      // Capture previous state for change detection (best-effort)
      if (r.savedFlow!.id > 0) {
        try {
          oldFlowRow = await _flowsRepo.getFlowById(r.savedFlow!.id);
        } catch (_) {
          oldFlowRow = null;
        }
      }

      // ✅ For imported flows (with plannedNotes), clear rules to prevent rule-based rescheduling
      // The rules are already cleared in _save() when widget.importData != null,
      // but we also check here as a safety measure
      final bool hasSnapshotEvents = r.plannedNotes.isNotEmpty;
      final bool isAiLocal = r.savedFlow?.shareId == 'ai-local';
      final rulesJson = (hasSnapshotEvents && !isAiLocal)
          ? jsonEncode([])
          : jsonEncode(r.savedFlow!.rules.map(ruleToJson).toList());

      final savedId = await repo.upsertFlow(
        id: r.savedFlow!.id > 0 ? r.savedFlow!.id : null,
        name: r.savedFlow!.name,
        color: r.savedFlow!.color.value,
        active: r.savedFlow!.active,
        startDate: r.savedFlow!.start,
        endDate: r.savedFlow!.end,
        notes: r.savedFlow!.notes,
        rules: rulesJson,
        isHidden: r.savedFlow!.isHidden,
        originType: r.originType,
        originFlowId: r.originFlowId,
        originShareId: r.originShareId ?? r.savedFlow!.shareId,
        originGenerationId: r.originGenerationId,
        rootFlowId: r.rootFlowId,
      );

      saved = _Flow(
        id: savedId,
        name: r.savedFlow!.name,
        color: r.savedFlow!.color,
        active: r.savedFlow!.active,
        rules: r.savedFlow!.rules,
        start: r.savedFlow!.start,
        end: r.savedFlow!.end,
        notes: r.savedFlow!.notes,
        shareId: r.savedFlow!.shareId,
        isHidden: r.savedFlow!.isHidden, // Preserve hidden status
      );

      if (r.originGenerationId != null) {
        try {
          await repo.flowCommit(
            generationId: r.originGenerationId!,
            flowId: savedId,
          );
        } catch (e) {
          if (kDebugMode) {
            debugPrint(
              '[persistFlowStudio] flow_commit failed for generation ${r.originGenerationId}: $e',
            );
          }
        }
      }

      final idx = _flows.indexWhere((f) => f.id == savedId);
      if (idx >= 0) {
        _flows[idx] = saved;
      } else {
        _flows.add(saved);
        if (savedId >= _nextFlowId) _nextFlowId = savedId + 1;
      }

      // Add verification logging
      if (kDebugMode) {
        debugPrint(
          '[persistFlowStudio] Saved flow $savedId "${saved.name}" with color=${saved.color.value.toRadixString(16)} to database',
        );
      }
    }

    // 3) Apply planned notes locally
    final flowId = saved?.id ?? r.savedFlow?.id ?? -1;
    final aiGenerated = oldFlowRow?.aiMetadata == null
        ? null
        : oldFlowRow!.aiMetadata?['generated'];
    final isAIFlow = aiGenerated is bool && aiGenerated;

    if (r.plannedNotes.isNotEmpty) {
      final repo2 = UserEventsRepo(Supabase.instance.client);

      // For AI-generated flows, wipe existing events first to avoid duplicates
      if (isAIFlow && flowId > 0) {
        try {
          await repo2.deleteByFlowId(flowId);
          if (kDebugMode) {
            debugPrint(
              '[persistFlowStudio] Cleared existing events for AI flow $flowId to avoid duplicates',
            );
          }
        } catch (e) {
          if (kDebugMode) {
            debugPrint(
              '[persistFlowStudio] Failed to clear events for AI flow $flowId: $e',
            );
          }
        }
      }

      for (final p in r.plannedNotes) {
        final n = p.note;
        final noteFlowId = (n.flowId ?? flowId) ?? -1;

        // Add to in-memory notes
        _addNote(
          p.ky,
          p.km,
          p.kd,
          n.title,
          n.detail,
          location: n.location,
          allDay: n.allDay,
          start: n.start,
          end: n.end,
          flowId: noteFlowId >= 0 ? noteFlowId : null,
          category: n.category,
          alertOffsetMinutes: n.alertOffsetMinutes,
        );

        // Persist to database
        final cid = EventCidUtil.buildClientEventId(
          ky: p.ky,
          km: p.km,
          kd: p.kd,
          title: n.title,
          startHour: n.start?.hour ?? 9,
          startMinute: n.start?.minute ?? 0,
          allDay: n.allDay,
          flowId: noteFlowId,
        );

        final gDay = KemeticMath.toGregorian(p.ky, p.km, p.kd);
        final startsAt = DateTime(
          gDay.year,
          gDay.month,
          gDay.day,
          n.start?.hour ?? 9,
          n.start?.minute ?? 0,
        );

        DateTime? endsAt;
        if (!n.allDay && n.end != null) {
          endsAt = DateTime(
            gDay.year,
            gDay.month,
            gDay.day,
            n.end!.hour,
            n.end!.minute,
          );
        } else if (!n.allDay) {
          endsAt = startsAt.add(const Duration(hours: 1));
        }

        final trimmedDetail = (n.detail ?? '').trim();
        final baseDetail = trimmedDetail.isEmpty ? null : trimmedDetail;
        final detailWithMeta = _encodeDetailWithMeta(
          baseDetail,
          alertMinutes: n.alertOffsetMinutes,
        );
        final detailToSave = detailWithMeta ?? baseDetail;

        final savedEvent = await repo2.upsertByClientId(
          clientEventId: cid,
          title: n.title,
          startsAtUtc: startsAt.toUtc(),
          detail: detailToSave,
          location: (n.location ?? '').trim().isEmpty ? null : n.location,
          allDay: n.allDay,
          endsAtUtc: endsAt?.toUtc(),
          flowLocalId: noteFlowId >= 0 ? noteFlowId : null,
          category: n.category,
          caller: 'persist_flow_studio',
        );

        await _scheduleAlertForEvent(
          note: n,
          ky: p.ky,
          km: p.km,
          kd: p.kd,
          clientEventId: savedEvent.clientEventId ?? cid,
          eventId: savedEvent.id,
        );
      }
    }

    // Use shared scheduler for flow notes if we have a saved flow
    if (saved != null && saved.active && saved.rules.isNotEmpty) {
      // If we have planned notes, skip rule-based scheduling to preserve titles/times.
      if (r.plannedNotes.isNotEmpty) {
        if (kDebugMode) {
          debugPrint(
            '[persistFlowStudio] ✅ Skipping scheduleFlowNotes - using plannedNotes with individual titles',
          );
        }
        setState(() {});
        _notifyDayViewDataChanged();
        return saved.id;
      }
      // If rules list was cleared (e.g., snapshot-only imports), skip scheduling.
      if (saved.rules.isEmpty) {
        if (kDebugMode) {
          debugPrint(
            '[persistFlowStudio] ✅ Skipping scheduleFlowNotes - flow has no rules (snapshot-only)',
          );
        }
        setState(() {});
        _notifyDayViewDataChanged();
        return saved.id;
      }
      try {
        // Check if this is an AI-generated flow before scheduling
        // (AI flows already have individually-titled events that shouldn't be regenerated)
        final flowRow = await _flowsRepo.getFlowById(saved.id);

        // Defensive type checking for ai_metadata.generated field
        final aiGenerated = flowRow?.aiMetadata?['generated'];
        final isAIFlow = aiGenerated is bool && aiGenerated == true;

        if (isAIFlow) {
          if (kDebugMode) {
            debugPrint(
              '[persistFlowStudio] ✅ Skipping scheduleFlowNotes for AI-generated flow ${saved.id} (preserving individual note titles)',
            );
          }

          // TODO: Add analytics once analytics service is integrated
          // Example: _analyticsService.logEvent('ai_flow_schedule_skipped', {'flowId': saved.id});
        } else {
          // Imported flow with only color change? Skip reschedule.
          if (saved.shareId != null &&
              oldFlowRow != null &&
              _isColorOnlyChange(oldFlowRow, saved)) {
            if (kDebugMode) {
              debugPrint(
                '[persistFlowStudio] ⚠️ Skipping reschedule for color-only change on imported flow ${saved.id}',
              );
            }
          } else {
            // Only regenerate notes for manually-created flows with recurring rules
            await scheduleFlowNotes(
              flowId: saved.id,
              rules: saved.rules,
              flowNotes: saved.notes,
              startDate: saved.start,
              endDate: saved.end,
            );

            if (kDebugMode) {
              debugPrint(
                '[persistFlowStudio] ✅ Scheduled recurring notes for flow ${saved.id}',
              );
            }
          }

          // TODO: Add analytics once analytics service is integrated
          // Example: _analyticsService.logEvent('flow_notes_scheduled', {
          //   'flowId': saved.id,
          //   'ruleCount': saved.rules.length,
          //   'dateRange': '${saved.start} to ${saved.end}',
          // });
        }
      } catch (e, stackTrace) {
        // Log error but don't crash - flow is already saved
        if (kDebugMode) {
          debugPrint(
            '[persistFlowStudio] ⚠️ Failed to check/schedule flow notes: $e',
          );
          debugPrint('Stack trace: $stackTrace');
        }

        // TODO: Add error tracking once analytics service is integrated
        // Example: _analyticsService.logError('flow_schedule_error', e, stackTrace);
      }
    }

    setState(() {});
    _notifyDayViewDataChanged();
    return saved?.id;
  }

  /// Schedules all note occurrences for a flow to the calendar
  /// This is the shared logic used by both Flow Studio and Inbox imports
  // Save a single (non-repeating) note only
  Future<({String clientEventId, String eventId})> _saveSingleNoteOnly({
    required int selYear,
    required int selMonth,
    required int selDay,
    required String title,
    String? detail,
    String? location,
    required bool allDay,
    TimeOfDay? startTime,
    TimeOfDay? endTime,
    Color? color,
    String? category,
    int alertMinutesBefore = _alertNoneMinutes,
  }) async {
    // Compute event start + alert time
    final gDay = KemeticMath.toGregorian(selYear, selMonth, selDay);
    final startLocal = allDay
        ? DateTime(gDay.year, gDay.month, gDay.day, 9, 0) // default 9:00 AM
        : DateTime(
            gDay.year,
            gDay.month,
            gDay.day,
            startTime!.hour,
            startTime!.minute,
          );
    final note = _Note(
      title: title,
      detail: detail,
      location: location,
      allDay: allDay,
      start: startTime,
      end: endTime,
      flowId: -1,
      manualColor: color,
      category: category,
      alertOffsetMinutes: alertMinutesBefore,
    );

    final alertAt = _alertDateTimeLocal(
      note: note,
      kYear: selYear,
      kMonth: selMonth,
      kDay: selDay,
    );

    // Build a simple text body: Location (if any) + Details (if any)
    final bodyLines = <String>[
      if (location != null && location.isNotEmpty) location,
      if (detail != null && detail.isNotEmpty) detail,
    ];
    final body = bodyLines.isEmpty ? null : bodyLines.join('\n');

    // Build canonical clientEventId for this manual note
    final String unifiedCid = _buildCid(
      ky: selYear,
      km: selMonth,
      kd: selDay,
      title: title,
      startHour: (allDay || startTime == null) ? null : startTime!.hour,
      startMinute: (allDay || startTime == null) ? null : startTime!.minute,
      allDay: allDay,
      flowId: -1,
    );

    await _ensureManualDeleteTombstonesLoaded();
    await _clearManualTombstone(unifiedCid);

    final encodedDetail = _encodeDetailWithMeta(
      detail,
      color: color,
      alertMinutes: alertMinutesBefore,
    );

    // Sync to Supabase and persist id/clientEventId
    final repo = UserEventsRepo(Supabase.instance.client);
    try {
      final endsAtUtc = (allDay || endTime == null)
          ? null
          : DateTime(
              gDay.year,
              gDay.month,
              gDay.day,
              endTime!.hour,
              endTime!.minute,
            ).toUtc();

      final updated = await repo.upsertByClientId(
        clientEventId: unifiedCid,
        title: title,
        startsAtUtc: startLocal.toUtc(),
        detail: encodedDetail,
        location: location,
        allDay: allDay,
        endsAtUtc: endsAtUtc,
        category: category,
        caller: 'save_single',
      );

      if (updated.id.isEmpty) {
        throw StateError('Supabase upsert returned empty id for $unifiedCid');
      }

      final savedClientEventId = updated.clientEventId ?? unifiedCid;

      _addNote(
        selYear,
        selMonth,
        selDay,
        title,
        detail,
        id: updated.id,
        clientEventId: savedClientEventId,
        location: location,
        allDay: allDay,
        start: startTime,
        end: endTime,
        manualColor: color,
        category: category,
        alertOffsetMinutes: alertMinutesBefore,
      );

      await _scheduleAlertForEvent(
        note: note.copyWith(
          id: updated.id,
          clientEventId: updated.clientEventId,
        ),
        ky: selYear,
        km: selMonth,
        kd: selDay,
        clientEventId: updated.clientEventId ?? unifiedCid,
        eventId: updated.id,
      );

      // Also log to app_events for analytics
      try {
        await repo.track(
          event: 'note_created',
          properties: {
            'title': title,
            if (detail != null && detail.isNotEmpty) 'body': detail,
            if (location != null && location.isNotEmpty) 'location': location,
            'all_day': allDay,
          },
          source: 'client',
        );
      } catch (e) {
        if (kDebugMode) {
          debugPrint('[SaveSingleNote] failed to log app_events: $e');
        }
      }
      return (clientEventId: savedClientEventId, eventId: updated.id);
    } catch (e, st) {
      try {
        await Notify.cancelNotificationForEvent(unifiedCid);
      } catch (cancelErr) {
        debugPrint(
          '[SaveSingleNote] failed to cancel notification for $unifiedCid after error: $cancelErr',
        );
      }
      debugPrint(
        '[SaveSingleNote] failed to save standalone note (cid=$unifiedCid): $e',
      );
      if (kDebugMode) {
        debugPrint('$st');
      }
      rethrow;
    }
  }

  Future<({String clientEventId, String eventId})> _updateSingleNoteOnly({
    required String existingEventId,
    required String? previousClientEventId,
    required int selYear,
    required int selMonth,
    required int selDay,
    required String title,
    String? detail,
    String? location,
    required bool allDay,
    TimeOfDay? startTime,
    TimeOfDay? endTime,
    Color? color,
    String? category,
    int alertMinutesBefore = _alertNoneMinutes,
  }) async {
    final gDay = KemeticMath.toGregorian(selYear, selMonth, selDay);
    final startLocal = allDay
        ? DateTime(gDay.year, gDay.month, gDay.day, 9, 0)
        : DateTime(
            gDay.year,
            gDay.month,
            gDay.day,
            startTime!.hour,
            startTime.minute,
          );
    final note = _Note(
      id: existingEventId,
      clientEventId: previousClientEventId,
      title: title,
      detail: detail,
      location: location,
      allDay: allDay,
      start: startTime,
      end: endTime,
      flowId: -1,
      manualColor: color,
      category: category,
      alertOffsetMinutes: alertMinutesBefore,
    );

    final unifiedCid = _buildCid(
      ky: selYear,
      km: selMonth,
      kd: selDay,
      title: title,
      startHour: (allDay || startTime == null) ? null : startTime.hour,
      startMinute: (allDay || startTime == null) ? null : startTime.minute,
      allDay: allDay,
      flowId: -1,
    );

    await _ensureManualDeleteTombstonesLoaded();
    await _clearManualTombstone(unifiedCid);

    final encodedDetail = _encodeDetailWithMeta(
      detail,
      color: color,
      alertMinutes: alertMinutesBefore,
    );

    final repo = UserEventsRepo(Supabase.instance.client);
    final endsAtUtc = (allDay || endTime == null)
        ? null
        : DateTime(
            gDay.year,
            gDay.month,
            gDay.day,
            endTime.hour,
            endTime.minute,
          ).toUtc();

    final updated = await repo.replace(
      id: existingEventId,
      clientEventId: unifiedCid,
      title: title,
      detail: encodedDetail,
      location: location,
      allDay: allDay,
      startsAt: startLocal,
      endsAt: endsAtUtc,
      category: category,
    );

    final savedClientEventId = updated.clientEventId ?? unifiedCid;
    if (previousClientEventId != null &&
        previousClientEventId != savedClientEventId) {
      try {
        await Notify.cancelNotificationForEvent(previousClientEventId);
      } catch (_) {}
    }

    _addNote(
      selYear,
      selMonth,
      selDay,
      title,
      detail,
      id: updated.id,
      clientEventId: savedClientEventId,
      location: location,
      allDay: allDay,
      start: startTime,
      end: endTime,
      manualColor: color,
      category: category,
      alertOffsetMinutes: alertMinutesBefore,
    );

    await _scheduleAlertForEvent(
      note: note.copyWith(id: updated.id, clientEventId: savedClientEventId),
      ky: selYear,
      km: selMonth,
      kd: selDay,
      clientEventId: savedClientEventId,
      eventId: updated.id,
    );

    return (clientEventId: savedClientEventId, eventId: updated.id);
  }

  // Save a repeating note as a hidden micro-flow
  Future<void> _saveRepeatingNoteAsHiddenFlow({
    required int selYear,
    required int selMonth,
    required int selDay,
    required String title,
    String? detail,
    String? location,
    required bool allDay,
    required TimeOfDay? startTime,
    required TimeOfDay? endTime,
    required NoteRepeatOption repeatOption,
    required SimpleRecurrenceFrequency customFrequency,
    required int customInterval,
    required NoteRepeatEndType endType,
    required DateTime? endDate,
    required int endCount,
    required Color color,
    String? category,
    int alertMinutesBefore = _alertNoneMinutes,
  }) async {
    // 1. First occurrence = selected Kemetic day -> Gregorian
    final DateTime firstOccurrence = KemeticMath.toGregorian(
      selYear,
      selMonth,
      selDay,
    );

    final DateTime now = DateUtils.dateOnly(DateTime.now());

    // 2. Determine horizon for recurrence generation and flow.end.
    late final DateTime horizonEnd;
    if (endType == NoteRepeatEndType.onDate && endDate != null) {
      horizonEnd = DateUtils.dateOnly(endDate);
    } else if (endType == NoteRepeatEndType.afterCount) {
      // Rough upper bound: assume worst-case yearly interval * count.
      horizonEnd = firstOccurrence.add(Duration(days: 365 * endCount));
    } else {
      // Never ends: use a sane horizon (e.g. 1 year out).
      horizonEnd = firstOccurrence.add(const Duration(days: 365));
    }

    // 3. Generate `_RuleDates` with Kemetic-aware recurrence logic.
    final _RuleDates rule = _buildNoteRuleDates(
      firstOccurrenceDate: firstOccurrence,
      repeatOption: repeatOption,
      customFrequency: customFrequency,
      customInterval: customInterval,
      endType: endType,
      endDate: endDate,
      endCount: endCount,
      allDay: allDay,
      startTime: startTime,
      endTime: endTime,
      horizonEnd: horizonEnd,
    );

    // 4. Guard: if we somehow got no dates, fall back to single note.
    if (rule.dates.isEmpty) {
      if (kDebugMode) {
        debugPrint(
          '[RepeatNote] Empty date set for repeating note "$title"; falling back to single note.',
        );
      }
      await _saveSingleNoteOnly(
        selYear: selYear,
        selMonth: selMonth,
        selDay: selDay,
        title: title,
        detail: detail,
        location: location,
        allDay: allDay,
        startTime: startTime,
        endTime: endTime,
        color: color,
        category: category,
      );
      return;
    }

    // 5. Create a hidden flow object in memory (micro-flow just for this note pattern).
    final flow = _Flow(
      id: -1, // Will be replaced by DB id
      name: title,
      color: color, // Use selected color
      active: true,
      rules: [rule],
      start: firstOccurrence,
      end: horizonEnd,
      notes: _encodeRepeatingNoteMetadata(
        detail: detail,
        location: location,
        category: category,
        alertMinutes: alertMinutesBefore,
      ),
      shareId: null,
      isHidden: true, // Critical: these never show in Flow Studio lists
    );

    final repo = UserEventsRepo(Supabase.instance.client);

    // 6. Persist the flow row to Supabase, storing rules as JSON.
    final rulesJson = jsonEncode([_CalendarPageState.ruleToJson(rule)]);

    final int flowId = await repo.upsertFlow(
      id: null,
      name: flow.name,
      color: flow.color.value,
      active: flow.active,
      startDate: flow.start,
      endDate: flow.end,
      notes: flow.notes,
      rules: rulesJson,
      isHidden: flow.isHidden,
    );

    // 7. Insert into in-memory _flows list with correct ID.
    final savedFlow = _Flow(
      id: flowId,
      name: flow.name,
      color: flow.color,
      active: flow.active,
      rules: flow.rules,
      start: flow.start,
      end: flow.end,
      notes: flow.notes,
      shareId: flow.shareId,
      isHidden: flow.isHidden,
    );

    _flows.add(savedFlow);
    if (flowId >= _nextFlowId) {
      _nextFlowId = flowId + 1;
    }

    // 8. Trigger materialization of events into user_events via the shared engine.
    await _triggerFlowSchedule(flowId);

    // 9. Refresh local caches so the new repeating note series shows up immediately.
    unawaited(_loadFromDisk(source: 'repeat_note_save'));
  }

  /// Universal date picker supporting Kemetic/Gregorian toggle
  Future<DateTime?> pickDateUniversal({
    required BuildContext context,
    required DateTime initialDate,
    bool allowPast = false,
    DateTime? firstDate,
    DateTime? lastDate,
  }) async {
    // Default to Gregorian mode for repeat-end selection
    bool localKemetic = false;

    // ---- Gregorian seed ----
    final now = DateUtils.dateOnly(DateTime.now());
    DateTime gSeed = initialDate;
    int gy = gSeed.year, gm = gSeed.month, gd = gSeed.day;

    // ---- Kemetic seed ----
    var kSeed = KemeticMath.fromGregorian(initialDate);
    int ky = kSeed.kYear, km = kSeed.kMonth, kd = kSeed.kDay;

    int _gregDayMax(int y, int m) => DateUtils.getDaysInMonth(y, m);
    int _kemDayMax(int year, int month) =>
        (month == 13) ? (KemeticMath.isLeapKemeticYear(year) ? 6 : 5) : 30;

    // ---- Controllers ----
    final gYearStart = now.year;
    final gYearCtrl = FixedExtentScrollController(
      initialItem: (gy - gYearStart).clamp(0, 399),
    );
    final gMonthCtrl = FixedExtentScrollController(
      initialItem: (gm - 1).clamp(0, 11),
    );
    final gDayCtrl = FixedExtentScrollController(
      initialItem: (gd - 1).clamp(0, 30),
    );

    final kYearStart = ky;
    final kYearCtrl = FixedExtentScrollController(
      initialItem: (ky - kYearStart).clamp(0, 400),
    );
    final kMonthCtrl = FixedExtentScrollController(
      initialItem: (km - 1).clamp(0, 12),
    );
    final kDayCtrl = FixedExtentScrollController(
      initialItem: (kd - 1).clamp(0, 29),
    );

    // ---------------------------------------------------------------------------
    // SHOW THE BOTTOM SHEET
    // ---------------------------------------------------------------------------
    final result = await showModalBottomSheet<DateTime>(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.black,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(16)),
      ),
      builder: (sheetCtx) {
        return StatefulBuilder(
          builder: (sheetCtx, setSheetState) {
            // Clamp wheels against month/day changes
            final gMax = _gregDayMax(gy, gm);
            if (gd > gMax) gd = gMax;
            final kMax = _kemDayMax(ky, km);
            if (kd > kMax) kd = kMax;

            // -------------------------------------------------------------------
            // Gregorian wheel
            // -------------------------------------------------------------------
            Widget _gregWheel() => SizedBox(
              height: 160,
              child: Row(
                children: [
                  // MONTH
                  Expanded(
                    flex: 4,
                    child: CupertinoPicker(
                      scrollController: gMonthCtrl,
                      itemExtent: 32,
                      looping: true,
                      backgroundColor: const Color(0x00121214),
                      onSelectedItemChanged: (i) {
                        setSheetState(() {
                          gm = (i % 12) + 1;
                          final mx = _gregDayMax(gy, gm);
                          if (gd > mx && gDayCtrl.hasClients) {
                            gd = mx;
                            WidgetsBinding.instance.addPostFrameCallback(
                              (_) => gDayCtrl.jumpToItem(gd - 1),
                            );
                          }
                        });
                      },
                      children: List.generate(
                        12,
                        (i) => Center(
                          child: GlossyText(
                            text: _gregMonthNames[i + 1],
                            style: const TextStyle(fontSize: 14),
                            gradient: silverGloss,
                          ),
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(width: 6),

                  // DAY
                  Expanded(
                    flex: 3,
                    child: CupertinoPicker(
                      scrollController: gDayCtrl,
                      itemExtent: 32,
                      looping: true,
                      backgroundColor: const Color(0x00121214),
                      onSelectedItemChanged: (i) {
                        setSheetState(() {
                          final mx = _gregDayMax(gy, gm);
                          gd = (i % mx) + 1;
                        });
                      },
                      children: List.generate(
                        _gregDayMax(gy, gm),
                        (i) => Center(
                          child: GlossyText(
                            text: '${i + 1}',
                            style: const TextStyle(fontSize: 14),
                            gradient: silverGloss,
                          ),
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(width: 6),

                  // YEAR
                  Expanded(
                    flex: 4,
                    child: CupertinoPicker(
                      scrollController: gYearCtrl,
                      itemExtent: 32,
                      looping: true,
                      backgroundColor: const Color(0x00121214),
                      onSelectedItemChanged: (i) {
                        setSheetState(() {
                          gy = gYearStart + i;
                          final mx = _gregDayMax(gy, gm);
                          if (gd > mx && gDayCtrl.hasClients) {
                            gd = mx;
                            WidgetsBinding.instance.addPostFrameCallback(
                              (_) => gDayCtrl.jumpToItem(gd - 1),
                            );
                          }
                        });
                      },
                      children: List.generate(40, (i) {
                        final yy = gYearStart + i;
                        return Center(
                          child: GlossyText(
                            text: '$yy',
                            style: const TextStyle(fontSize: 14),
                            gradient: silverGloss,
                          ),
                        );
                      }),
                    ),
                  ),
                ],
              ),
            );

            // -------------------------------------------------------------------
            // Kemetic wheel
            // -------------------------------------------------------------------
            Widget _kemWheel() => SizedBox(
              height: 160,
              child: Row(
                children: [
                  // MONTH
                  Expanded(
                    flex: 4,
                    child: CupertinoPicker(
                      scrollController: kMonthCtrl,
                      itemExtent: 32,
                      looping: true,
                      backgroundColor: const Color(0x00121214),
                      onSelectedItemChanged: (i) {
                        setSheetState(() {
                          km = (i % 13) + 1;
                          final mx = _kemDayMax(ky, km);
                          if (kd > mx && kDayCtrl.hasClients) {
                            kd = mx;
                            WidgetsBinding.instance.addPostFrameCallback(
                              (_) => kDayCtrl.jumpToItem(kd - 1),
                            );
                          }
                        });
                      },
                      children: List.generate(
                        13,
                        (i) => Center(
                          child: MonthNameText(
                            getMonthById(i + 1).displayFull,
                            style: const TextStyle(fontSize: 14),
                          ),
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(width: 6),

                  // DAY
                  Expanded(
                    flex: 3,
                    child: CupertinoPicker(
                      scrollController: kDayCtrl,
                      itemExtent: 32,
                      looping: true,
                      backgroundColor: const Color(0x00121214),
                      onSelectedItemChanged: (i) {
                        setSheetState(() {
                          final mx = _kemDayMax(ky, km);
                          kd = (i % mx) + 1;
                        });
                      },
                      children: List.generate(
                        _kemDayMax(ky, km),
                        (i) => Center(
                          child: GlossyText(
                            text: '${i + 1}',
                            style: const TextStyle(fontSize: 14),
                            gradient: silverGloss,
                          ),
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(width: 6),

                  // YEAR
                  Expanded(
                    flex: 4,
                    child: CupertinoPicker(
                      scrollController: kYearCtrl,
                      itemExtent: 32,
                      looping: true,
                      backgroundColor: const Color(0x00121214),
                      onSelectedItemChanged: (i) {
                        setSheetState(() {
                          ky = kYearStart + i;
                          final mx = _kemDayMax(ky, km);
                          if (kd > mx && kDayCtrl.hasClients) {
                            kd = mx;
                            WidgetsBinding.instance.addPostFrameCallback(
                              (_) => kDayCtrl.jumpToItem(kd - 1),
                            );
                          }
                        });
                      },
                      children: List.generate(401, (i) {
                        final y = kYearStart + i;
                        final last = (km == 13)
                            ? (KemeticMath.isLeapKemeticYear(y) ? 6 : 5)
                            : 30;
                        final yStart = KemeticMath.toGregorian(y, km, 1).year;
                        final yEnd = KemeticMath.toGregorian(y, km, last).year;
                        final label = (yStart == yEnd)
                            ? '$yStart'
                            : '$yStart/$yEnd';
                        return Center(
                          child: GlossyText(
                            text: label,
                            style: const TextStyle(fontSize: 14),
                            gradient: silverGloss,
                          ),
                        );
                      }),
                    ),
                  ),
                ],
              ),
            );

            // -------------------------------------------------------------------
            // UI SHEET CONTENT
            // -------------------------------------------------------------------
            return Padding(
              padding: EdgeInsets.only(
                left: 16,
                right: 16,
                top: 12,
                bottom: MediaQuery.of(sheetCtx).viewInsets.bottom + 12,
              ),
              child: Column(
                mainAxisSize: MainAxisSize.min,
                children: [
                  // drag handle
                  Container(
                    width: 36,
                    height: 4,
                    margin: const EdgeInsets.only(bottom: 12),
                    decoration: BoxDecoration(
                      color: Colors.white24,
                      borderRadius: BorderRadius.circular(2),
                    ),
                  ),

                  // mode toggle
                  CupertinoSegmentedControl<bool>(
                    groupValue: localKemetic,
                    padding: const EdgeInsets.all(2),
                    children: const {
                      true: Padding(
                        padding: EdgeInsets.symmetric(
                          horizontal: 10,
                          vertical: 6,
                        ),
                        child: Text('Kemetic'),
                      ),
                      false: Padding(
                        padding: EdgeInsets.symmetric(
                          horizontal: 10,
                          vertical: 6,
                        ),
                        child: Text('Gregorian'),
                      ),
                    },
                    onValueChanged: (v) {
                      setSheetState(() {
                        if (v) {
                          // Switch to Kemetic
                          final gNow = DateTime(gy, gm, gd);
                          final k = KemeticMath.fromGregorian(gNow);
                          ky = k.kYear;
                          km = k.kMonth;
                          kd = k.kDay;
                          final kMax = _kemDayMax(ky, km);
                          if (kd > kMax) kd = kMax;
                          localKemetic = true;

                          WidgetsBinding.instance.addPostFrameCallback((_) {
                            kYearCtrl.jumpToItem(
                              (ky - kYearStart).clamp(0, 400),
                            );
                            kMonthCtrl.jumpToItem((km - 1).clamp(0, 12));
                            kDayCtrl.jumpToItem((kd - 1).clamp(0, 29));
                          });
                        } else {
                          // Switch to Gregorian
                          final g = KemeticMath.toGregorian(ky, km, kd);
                          gy = g.year;
                          gm = g.month;
                          gd = g.day;
                          final gMax = _gregDayMax(gy, gm);
                          if (gd > gMax) gd = gMax;
                          localKemetic = false;

                          WidgetsBinding.instance.addPostFrameCallback((_) {
                            gYearCtrl.jumpToItem(
                              (gy - gYearStart).clamp(0, 39),
                            );
                            gMonthCtrl.jumpToItem((gm - 1).clamp(0, 11));
                            gDayCtrl.jumpToItem((gd - 1).clamp(0, 30));
                          });
                        }
                      });
                    },
                  ),

                  const SizedBox(height: 10),

                  GlossyText(
                    text: localKemetic
                        ? 'Pick date (Kemetic)'
                        : 'Pick date (Gregorian)',
                    style: const TextStyle(
                      fontSize: 16,
                      fontWeight: FontWeight.w600,
                    ),
                    gradient: localKemetic ? goldGloss : blueGloss,
                  ),

                  const SizedBox(height: 8),

                  localKemetic ? _kemWheel() : _gregWheel(),

                  const SizedBox(height: 12),

                  Row(
                    children: [
                      // CANCEL
                      Expanded(
                        child: OutlinedButton(
                          style: OutlinedButton.styleFrom(
                            foregroundColor: Colors.white,
                            side: const BorderSide(color: silver, width: 1.25),
                          ),
                          onPressed: () => Navigator.pop(sheetCtx),
                          child: const Text('Cancel'),
                        ),
                      ),
                      const SizedBox(width: 8),

                      // USE THIS DATE
                      Expanded(
                        child: ElevatedButton(
                          style: ElevatedButton.styleFrom(
                            backgroundColor: localKemetic ? _gold : _blue,
                            foregroundColor: Colors.black,
                          ),
                          onPressed: () {
                            final DateTime chosen = localKemetic
                                ? KemeticMath.toGregorian(ky, km, kd)
                                : DateUtils.dateOnly(DateTime(gy, gm, gd));

                            // Apply constraints
                            DateTime finalResult = chosen;
                            if (!allowPast &&
                                firstDate != null &&
                                finalResult.isBefore(firstDate)) {
                              finalResult = firstDate;
                            }
                            if (lastDate != null &&
                                finalResult.isAfter(lastDate)) {
                              finalResult = lastDate;
                            }

                            Navigator.pop(sheetCtx, finalResult);
                          },
                          child: const Text('Use this date'),
                        ),
                      ),
                    ],
                  ),
                ],
              ),
            );
          },
        );
      },
    );

    return result;
  }

  /// Trigger function: central place to (re)schedule events for a flow.
  ///
  /// This is the only method that should call `scheduleFlowNotes` directly.
  /// It is used by:
  ///  - Flow Studio saves/updates
  ///  - Repeating notes (hidden micro-flows)
  Future<void> _triggerFlowSchedule(int flowId) async {
    _Flow flow;

    try {
      flow = _flows.firstWhere((f) => f.id == flowId);
    } catch (_) {
      if (kDebugMode) {
        debugPrint(
          '[triggerFlowSchedule] Flow $flowId not found in _flows; skipping schedule.',
        );
      }
      return;
    }

    // If flow is inactive or has no rules, just clear its events.
    if (!flow.active || flow.rules.isEmpty) {
      if (kDebugMode) {
        debugPrint(
          '[triggerFlowSchedule] Flow $flowId inactive or has no rules; deleting events.',
        );
      }
      final repo = UserEventsRepo(Supabase.instance.client);
      await repo.deleteByFlowId(flowId);
      return;
    }

    if (kDebugMode) {
      debugPrint(
        '[triggerFlowSchedule] Scheduling flow $flowId with ${flow.rules.length} rules',
      );
    }

    await scheduleFlowNotes(
      flowId: flow.id,
      rules: flow.rules,
      flowNotes: flow.notes,
      startDate: flow.start,
      endDate: flow.end,
    );
  }

  Future<void> scheduleFlowNotes({
    required int flowId,
    required List<FlowRule> rules,
    required String? flowNotes,
    DateTime? startDate,
    DateTime? endDate,
  }) async {
    final repo = UserEventsRepo(Supabase.instance.client);
    final scheduleStart = startDate ?? DateTime.now();
    final scheduleEnd =
        endDate ??
        scheduleStart.add(const Duration(days: 90)); // Default 90 days

    if (kDebugMode) {
      debugPrint(
        '[scheduleFlowNotes] Starting for flowId=$flowId from $scheduleStart to $scheduleEnd',
      );
    }

    // Look up flow object for name and metadata
    _Flow? flow;
    try {
      flow = _flows.firstWhere((f) => f.id == flowId);
    } catch (_) {
      flow = null;
    }

    final flowStart = flow?.start ?? DateTime(1970);
    final flowEnd = flow?.end ?? DateTime(2100);
    final hasOverlap =
        !flowEnd.isBefore(scheduleStart) && !flowStart.isAfter(scheduleEnd);
    if (!hasOverlap) {
      if (kDebugMode) {
        debugPrint(
          '[scheduleFlowNotes] ⚠️ No overlap: flow ($flowStart-$flowEnd) vs schedule ($scheduleStart-$scheduleEnd)',
        );
      }
      return;
    }

    String noteTitle = flow?.name ?? 'Flow Event';
    String? noteDetail;
    String? noteLocation;
    int? noteAlertMinutes;

    // Decode flow.notes to extract detail and location for repeating notes
    if (flowNotes != null && flowNotes.isNotEmpty) {
      try {
        // Try JSON first (for repeating notes)
        final meta = jsonDecode(flowNotes) as Map<String, dynamic>;
        if (meta['kind'] == 'repeating_note') {
          noteDetail = (meta['detail'] as String?)?.trim();
          noteLocation = (meta['location'] as String?)?.trim();
          noteAlertMinutes = (meta['alertMinutes'] as num?)?.toInt();
        } else {
          // Legacy flowNotes format - try notesDecode
          try {
            final decoded = notesDecode(flowNotes);
            if (decoded.overview.isNotEmpty) noteDetail = decoded.overview;
          } catch (_) {
            // Ignore if decode fails
          }
        }
      } catch (_) {
        // Not JSON, try legacy format
        try {
          final decoded = notesDecode(flowNotes);
          if (decoded.overview.isNotEmpty) noteDetail = decoded.overview;
        } catch (_) {
          // Ignore if both fail
        }
      }
    }

    // Build candidate events first; only delete/insert if we have any.
    final candidateEvents = <_CandidateEvent>[];
    try {
      var date = scheduleStart;
      while (!date.isAfter(scheduleEnd)) {
        final kDate = KemeticMath.fromGregorian(date);

        for (final rule in rules) {
          if (rule.matches(
            ky: kDate.kYear,
            km: kDate.kMonth,
            kd: kDate.kDay,
            g: date,
          )) {
            final startHour = rule.allDay ? 9 : (rule.start?.hour ?? 9);
            final startMinute = rule.allDay ? 0 : (rule.start?.minute ?? 0);

            final detailWithMeta = _encodeDetailWithMeta(
              noteDetail,
              alertMinutes: noteAlertMinutes,
            );

            final cid = _buildCid(
              ky: kDate.kYear,
              km: kDate.kMonth,
              kd: kDate.kDay,
              title: noteTitle,
              startHour: startHour,
              startMinute: startMinute,
              allDay: rule.allDay,
              flowId: flowId,
            );

            final startsAt = DateTime(
              date.year,
              date.month,
              date.day,
              startHour,
              startMinute,
            );

            DateTime? endsAt;
            if (!rule.allDay) {
              if (rule.end != null) {
                endsAt = DateTime(
                  date.year,
                  date.month,
                  date.day,
                  rule.end!.hour,
                  rule.end!.minute,
                );
              } else {
                // Default to 1 hour if end is missing
                endsAt = DateTime(
                  date.year,
                  date.month,
                  date.day,
                  startHour,
                  startMinute,
                ).add(const Duration(hours: 1));
              }
            }

            candidateEvents.add(
              _CandidateEvent(
                clientEventId: cid,
                title: noteTitle,
                startsAtUtc: startsAt.toUtc(),
                endsAtUtc: endsAt?.toUtc(),
                detail: detailWithMeta ?? noteDetail,
                location: noteLocation,
                allDay: rule.allDay,
                flowLocalId: flowId,
              ),
            );
          }
        }

        date = date.add(const Duration(days: 1));
      }
    } catch (e, stack) {
      if (kDebugMode) {
        debugPrint(
          '[scheduleFlowNotes] ⚠️ Generation failed for flowId=$flowId: $e',
        );
        debugPrint(stack.toString());
      }
      return;
    }

    if (candidateEvents.isEmpty) {
      if (kDebugMode) {
        debugPrint(
          '[scheduleFlowNotes] ⚠️ No events generated for flowId=$flowId; skipping delete.',
        );
      }
      return;
    }

    try {
      // Clear existing scheduled notes for this flow after successful generation
      await repo.deleteByFlowId(flowId, fromDate: scheduleStart.toUtc());
      await repo.track(
        event: 'flow_rescheduled',
        properties: {'flow_id': flowId, 'v': kAppEventsSchemaVersion},
      );

      for (final ev in candidateEvents) {
        final savedEvent = await repo.upsertByClientId(
          clientEventId: ev.clientEventId,
          title: ev.title,
          startsAtUtc: ev.startsAtUtc,
          detail: ev.detail,
          location: ev.location,
          allDay: ev.allDay,
          endsAtUtc: ev.endsAtUtc,
          flowLocalId: ev.flowLocalId,
          caller: 'schedule_flow_notes',
        );

        final decodedMeta = _decodeDetailMetadata(ev.detail);
        final localStart = ev.startsAtUtc.toLocal();
        final kDate = KemeticMath.fromGregorian(localStart);
        final note = _Note(
          title: ev.title,
          detail: decodedMeta.detail ?? ev.detail,
          location: ev.location,
          allDay: ev.allDay,
          start: ev.allDay ? null : TimeOfDay.fromDateTime(localStart),
          end: ev.endsAtUtc == null
              ? null
              : TimeOfDay.fromDateTime(ev.endsAtUtc!.toLocal()),
          flowId: ev.flowLocalId,
          alertOffsetMinutes: decodedMeta.alertMinutes ?? _alertNoneMinutes,
        );

        await _scheduleAlertForEvent(
          note: note,
          ky: kDate.kYear,
          km: kDate.kMonth,
          kd: kDate.kDay,
          clientEventId: savedEvent.clientEventId ?? ev.clientEventId,
          eventId: savedEvent.id,
        );
      }

      if (kDebugMode) {
        debugPrint(
          '[scheduleFlowNotes] Scheduled ${candidateEvents.length} notes for flowId=$flowId',
        );
      }
    } catch (e, stack) {
      if (kDebugMode) {
        debugPrint(
          '[scheduleFlowNotes] ⚠️ CRITICAL: delete/insert failed for flowId=$flowId: $e',
        );
        debugPrint(stack.toString());
      }
    }
  }

  @override
  Widget build(BuildContext context) {
    // ✅ HARDENING 2: Gate build until state is restored to prevent race condition
    if (!_restored) {
      return const SizedBox.shrink();
    }

    _buildCount++;
    final kToday = _today;
    final size = MediaQuery.sizeOf(context);
    final orientation = MediaQuery.orientationOf(context);
    final isLandscape = orientation == Orientation.landscape;
    // Landscape grid only on phone-sized screens; tablets/desktop stay on portrait layout.
    final useGrid = isLandscape && size.shortestSide < 600;
    if (!useGrid) {
      _landscapeTodayAction = null;
    }

    // ========================================
    // DEBUG: Log orientation changes
    // ========================================
    if (_lastOrientation != null && _lastOrientation != orientation) {
      if (kDebugMode) {
        print('\n' + '🔄' * 30);
        print('ORIENTATION CHANGED!');
        print('From: $_lastOrientation → To: $orientation');
        print('Navigator canPop: ${Navigator.canPop(context)}');
        print(
          'Modal route active: ${ModalRoute.of(context)?.isCurrent ?? false}',
        );
        print('🔄' * 30 + '\n');
      }

      // ✅ FIX 1: Scroll to saved month when switching to portrait
      // _centerMonth() already uses addPostFrameCallback internally, so direct call is safe
      if (orientation == Orientation.portrait &&
          _lastViewKy != null &&
          _lastViewKm != null) {
        if (kDebugMode) {
          print(
            '📜 [CALENDAR] Scrolling to saved month: $_lastViewKy-$_lastViewKm',
          );
        }
        _centerMonth(_lastViewKy!, _lastViewKm!);
      }
      if (!_rememberLastView && orientation == Orientation.portrait) {
        // When switching into portrait without persistence, hide until we recentre on today.
        _portraitRecenterPending = true;
      }
    }
    _lastOrientation = orientation;

    if (useGrid) {
      debugPrint('📱 Rendering: LandscapeMonthView (build #$_buildCount)');

      // ✅ FIX 5: Only call if state is missing (optimization)
      // The method already has a guard, but this prevents unnecessary function calls
      // ✅ FIX 6: Also prevent during landscape updates to avoid side effects
      if (!_isUpdatingFromLandscape &&
          (_lastViewKy == null || _lastViewKm == null)) {
        _updateCenteredMonthWide();
      }

      final ky = _lastViewKy ?? kToday.kYear;
      final km = _lastViewKm ?? kToday.kMonth;

      if (kDebugMode) {
        print('\n📱 [CALENDAR] Building LandscapeMonthView');
        print('   initialKy: $ky');
        print('   initialKm: $km');
        print('   initialKd: null');
        print(
          '   onAddNote callback: ${_openDaySheet != null ? "PROVIDED" : "NULL"}',
        );
      }

      return Scaffold(
        backgroundColor: _bg,
        appBar: _buildCalendarAppBar(
          useLandscapeGrid: true,
          titleOverride: _buildLandscapeCalendarTitle(ky, km),
        ),
        body: LandscapeMonthView(
          embeddedInCalendarScaffold: true,
          initialKy: ky,
          initialKm: km,
          initialKd: _lastViewKd ?? _today.kDay, // ✅ Highlight current day
          showGregorian: _showGregorian,
          dataVersion: _dayViewDataVersion,
          notesForDay: (ky, km, kd) {
            final notes = _getNotes(ky, km, kd);
            return notes
                .map(
                  (n) => NoteData(
                    id: n.id?.toString(),
                    clientEventId: n.clientEventId,
                    title: n.title,
                    detail: n.detail,
                    location: n.location,
                    allDay: n.allDay,
                    start: n.start,
                    end: n.end,
                    flowId: n.flowId,
                    manualColor: n.manualColor,
                    category: n.category,
                    isReminder: n.isReminder,
                    reminderId: n.reminderId,
                  ),
                )
                .toList();
          },
          flowIndex: _buildFlowIndex(),
          getMonthName: (km) => getMonthById(km).displayFull,
          onManageFlows: _getMyFlowsCallback(),
          onAddNote: (ky, km, kd) {
            if (kDebugMode) {
              print('\n🎯 [CALLBACK] onAddNote received from landscape');
              print('   Date: $ky-$km-$kd');
            }
            _openDaySheet(ky, km, kd, allowDateChange: true);
          },
          onMonthChanged: _handleLandscapeMonthChanged, // ✅ ADD CALLBACK
          onTodayActionChanged: (action) {
            _landscapeTodayAction = action;
          },
          onDeleteNote: (ky, km, kd, evt) async =>
              _deleteNoteByEvent(ky, km, kd, evt),
          onEditNote: (ky, km, kd, evt) async {
            await _editNoteByEvent(ky, km, kd, evt);
          },
          onEditReminder: (id) async => _editReminderById(id),
          onEndReminder: (id) async => _endReminderRule(id),
          onShareReminder: (evt) async => _shareNoteSimple(evt),
          onShareNote: (evt) async {
            await _shareNoteSimple(evt);
          },
          onAppendToJournal: _journalInitialized
              ? (text) => _journalController.appendToToday(text)
              : null,
          onEndFlow: (id) => _endFlow(id),
          onSaveFlow: _saveFlowById,
        ),
      );
    }

    final scaffold = Scaffold(
      backgroundColor: _bg,
      appBar: _buildCalendarAppBar(useLandscapeGrid: false),
      body: _buildBodyWithJournal(),
    );

    Widget content = scaffold;

    final calendarMonthCoachmarkTargetKey = _calendarMonthCoachmarkTargetKey;
    if (_showCalendarMonthCoachmark &&
        calendarMonthCoachmarkTargetKey != null) {
      content = Stack(
        children: [
          content,
          Positioned.fill(
            child: CalendarMonthCoachmark(
              targetKey: calendarMonthCoachmarkTargetKey,
              onTargetTap: _handleCalendarMonthCoachmarkTargetTap,
            ),
          ),
        ],
      );
    }

    if (_showCalendarToggleCoachmark) {
      content = Stack(
        children: [
          content,
          Positioned.fill(
            child: CalendarToggleCoachmark(
              targetKey: _calendarToggleKey,
              onTargetTap: _handleCalendarToggleTapped,
            ),
          ),
        ],
      );
    }

    if (_showOnboarding) {
      content = Stack(
        children: [
          content,
          Positioned.fill(
            child: OnboardingOverlay(
              slides: _buildOnboardingSlides(),
              onSkip: _handleOnboardingSkip,
              onComplete: _handleOnboardingComplete,
            ),
          ),
        ],
      );
    }

    return content;
  }

  Widget _buildBodyWithJournal() {
    final isPortrait =
        MediaQuery.of(context).orientation == Orientation.portrait;
    final allowTouchPinchGestures = useExpandedTouchTargets(context);
    final allowGlobalScaleGestures = useGlobalScaleGestures(context);
    if (_portraitRecenterPending && isPortrait) {
      _ensurePortraitCentered();
    }

    final scrollView = Offstage(
      offstage: _portraitRecenterPending && isPortrait,
      child: _buildCalendarScrollView(),
    );

    final content = PinchGestureSurface(
      enableTouchPinch: allowTouchPinchGestures,
      enableGlobalScaleGestures: allowGlobalScaleGestures,
      onScaleStart: _onScaleStart,
      onScaleUpdate: _onScaleUpdate,
      onScaleEnd: _onScaleEnd,
      child: scrollView,
    );

    return Stack(
      children: [
        content,
        _buildPlannerSwipeGate(),
        _buildProfileSwipeGate(),
        const PendingEventInviteOverlay(),
        if (_reflectionPrompt != null) _buildReflectionBadge(),
      ],
    );
  }

  Widget _buildPlannerSwipeGate() {
    return PageNavigationEdgeSwipe(
      direction: PageNavigationSwipeDirection.leftToRight,
      enabled: !_plannerNavigationInFlight,
      onCommit: () {
        unawaited(_openPlannerPage(edgeSwipeTransition: true));
      },
    );
  }

  Widget _buildProfileSwipeGate() {
    return PageNavigationEdgeSwipe(
      direction: PageNavigationSwipeDirection.rightToLeft,
      enabled: !_profileNavigationInFlight,
      onCommit: () {
        unawaited(_openProfile(context, openedFromCalendarSwipe: true));
      },
    );
  }

