class _MaatFlowTemplateDetailPage extends StatefulWidget {
  const _MaatFlowTemplateDetailPage({
    required this.template,
    required this.addInstance,
    super.key,
  });

  final _MaatFlowTemplate template;
  final Future<int> Function({
    required _MaatFlowTemplate template,
    DateTime? startDate,
    bool? useKemetic,
    TrackSkyTimeZone? trackSkyTimeZone,
    int? alertMinutesBefore,
  })
  addInstance;

  @override
  State<_MaatFlowTemplateDetailPage> createState() =>
      _MaatFlowTemplateDetailPageState();
}

class _MaatFlowTemplateDetailPageState
    extends State<_MaatFlowTemplateDetailPage> {
  late TrackSkyTimeZone _previewTrackSkyTimeZone;
  Future<TrackSkyFlowData>? _trackSkyFuture;

  @override
  void initState() {
    super.initState();
    _previewTrackSkyTimeZone = detectTrackSkyTimeZone();
    if (widget.template.kind == _MaatFlowTemplateKind.trackSky) {
      _trackSkyFuture = loadTrackSkyFlowData(_previewTrackSkyTimeZone);
    }
  }

  String _fmtGregorian(DateTime d) =>
      '${d.year}-${d.month.toString().padLeft(2, '0')}-${d.day.toString().padLeft(2, '0')}';

  String _kemeticLabelFor(DateTime g) {
    final k = KemeticMath.fromGregorian(g);
    final lastDay = (k.kMonth == 13)
        ? (KemeticMath.isLeapKemeticYear(k.kYear) ? 6 : 5)
        : 30;
    final yStart = KemeticMath.toGregorian(k.kYear, k.kMonth, 1).year;
    final yEnd = KemeticMath.toGregorian(k.kYear, k.kMonth, lastDay).year;
    final yLabel = (yStart == yEnd) ? '$yStart' : '$yStart/$yEnd';
    final month = getMonthById(k.kMonth).displayFull;
    return '$month ${k.kDay} • $yLabel';
  }

  bool _useKemetic = false;
  DateTime? _picked;

  Future<void> _pickDate() async {
    bool localKemetic = _useKemetic;

    final now = DateUtils.dateOnly(DateTime.now());
    DateTime gSeed =
        _picked ??
        (() {
          int y = now.year, m = now.month, d = now.day + 1;
          final maxD = DateUtils.getDaysInMonth(y, m);
          if (d > maxD) {
            d = 1;
            m = (m == 12) ? 1 : m + 1;
            if (m == 1) y++;
          }
          return DateTime(y, m, d);
        })();
    int gy = gSeed.year, gm = gSeed.month, gd = gSeed.day;

    var kSeed = KemeticMath.fromGregorian(
      _picked ?? now.add(const Duration(days: 1)),
    );
    int ky = kSeed.kYear, km = kSeed.kMonth, kd = kSeed.kDay;

    int gregDayMax(int y, int m) => DateUtils.getDaysInMonth(y, m);
    int kemDayMax(int year, int month) =>
        (month == 13) ? (KemeticMath.isLeapKemeticYear(year) ? 6 : 5) : 30;

    final int gYearStart = now.year;
    final gYearCtrl = FixedExtentScrollController(
      initialItem: (gy - gYearStart).clamp(0, 399),
    );
    final gMonthCtrl = FixedExtentScrollController(
      initialItem: (gm - 1).clamp(0, 11),
    );
    final gDayCtrl = FixedExtentScrollController(
      initialItem: (gd - 1).clamp(0, 30),
    );

    final int kYearStart = ky;
    final kYearCtrl = FixedExtentScrollController(
      initialItem: (ky - kYearStart).clamp(0, 400),
    );
    final kMonthCtrl = FixedExtentScrollController(
      initialItem: (km - 1).clamp(0, 12),
    );
    final kDayCtrl = FixedExtentScrollController(
      initialItem: (kd - 1).clamp(0, 29),
    );

    await showModalBottomSheet(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.black,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(16)),
      ),
      builder: (sheetCtx) {
        return StatefulBuilder(
          builder: (sheetCtx, setSheetState) {
            final gMax = gregDayMax(gy, gm);
            if (gd > gMax) gd = gMax;
            final kMax = kemDayMax(ky, km);
            if (kd > kMax) kd = kMax;

            Widget gregWheel() => SizedBox(
              height: 160,
              child: Row(
                children: [
                  Expanded(
                    flex: 4,
                    child: CupertinoPicker(
                      scrollController: gMonthCtrl,
                      itemExtent: 32,
                      looping: true,
                      backgroundColor: const Color(0x00121214),
                      onSelectedItemChanged: (i) {
                        setSheetState(() {
                          gm = (i % 12) + 1;
                          final mx = gregDayMax(gy, gm);
                          if (gd > mx && gDayCtrl.hasClients) {
                            gd = mx;
                            WidgetsBinding.instance.addPostFrameCallback(
                              (_) => gDayCtrl.jumpToItem(gd - 1),
                            );
                          }
                        });
                      },
                      children: List.generate(12, (i) {
                        return Center(
                          child: GlossyText(
                            text: _gregMonthNames[i + 1],
                            style: const TextStyle(fontSize: 14),
                            gradient: silverGloss,
                          ),
                        );
                      }),
                    ),
                  ),
                  const SizedBox(width: 6),
                  Expanded(
                    flex: 3,
                    child: CupertinoPicker(
                      scrollController: gDayCtrl,
                      itemExtent: 32,
                      looping: true,
                      backgroundColor: const Color(0x00121214),
                      onSelectedItemChanged: (i) {
                        setSheetState(() {
                          final mx = gregDayMax(gy, gm);
                          gd = (i % mx) + 1;
                        });
                      },
                      children: List.generate(gregDayMax(gy, gm), (i) {
                        final dd = i + 1;
                        return Center(
                          child: GlossyText(
                            text: '$dd',
                            style: const TextStyle(fontSize: 14),
                            gradient: silverGloss,
                          ),
                        );
                      }),
                    ),
                  ),
                  const SizedBox(width: 6),
                  Expanded(
                    flex: 4,
                    child: CupertinoPicker(
                      scrollController: gYearCtrl,
                      itemExtent: 32,
                      looping: true,
                      backgroundColor: const Color(0x00121214),
                      onSelectedItemChanged: (i) {
                        setSheetState(() {
                          gy = gYearStart + i;
                          final mx = gregDayMax(gy, gm);
                          if (gd > mx && gDayCtrl.hasClients) {
                            gd = mx;
                            WidgetsBinding.instance.addPostFrameCallback(
                              (_) => gDayCtrl.jumpToItem(gd - 1),
                            );
                          }
                        });
                      },
                      children: List.generate(40, (i) {
                        final yy = gYearStart + i;
                        return Center(
                          child: GlossyText(
                            text: '$yy',
                            style: const TextStyle(fontSize: 14),
                            gradient: silverGloss,
                          ),
                        );
                      }),
                    ),
                  ),
                ],
              ),
            );

            Widget kemWheel() => SizedBox(
              height: 160,
              child: Row(
                children: [
                  Expanded(
                    flex: 4,
                    child: CupertinoPicker(
                      scrollController: kMonthCtrl,
                      itemExtent: 32,
                      looping: true,
                      backgroundColor: const Color(0x00121214),
                      onSelectedItemChanged: (i) {
                        setSheetState(() {
                          km = (i % 13) + 1;
                          final mx = kemDayMax(ky, km);
                          if (kd > mx && kDayCtrl.hasClients) {
                            kd = mx;
                            WidgetsBinding.instance.addPostFrameCallback(
                              (_) => kDayCtrl.jumpToItem(kd - 1),
                            );
                          }
                        });
                      },
                      children: List.generate(13, (i) {
                        final m = i + 1;
                        return Center(
                          child: MonthNameText(
                            getMonthById(m).displayFull,
                            style: const TextStyle(fontSize: 14),
                          ),
                        );
                      }),
                    ),
                  ),
                  const SizedBox(width: 6),
                  Expanded(
                    flex: 3,
                    child: CupertinoPicker(
                      scrollController: kDayCtrl,
                      itemExtent: 32,
                      looping: true,
                      backgroundColor: const Color(0x00121214),
                      onSelectedItemChanged: (i) {
                        setSheetState(() {
                          final mx = kemDayMax(ky, km);
                          kd = (i % mx) + 1;
                        });
                      },
                      children: List.generate(kemDayMax(ky, km), (i) {
                        final dd = i + 1;
                        return Center(
                          child: GlossyText(
                            text: '$dd',
                            style: const TextStyle(fontSize: 14),
                            gradient: silverGloss,
                          ),
                        );
                      }),
                    ),
                  ),
                  const SizedBox(width: 6),
                  Expanded(
                    flex: 4,
                    child: CupertinoPicker(
                      scrollController: kYearCtrl,
                      itemExtent: 32,
                      looping: true,
                      backgroundColor: const Color(0x00121214),
                      onSelectedItemChanged: (i) {
                        setSheetState(() {
                          ky = kYearStart + i;
                          final mx = kemDayMax(ky, km);
                          if (kd > mx && kDayCtrl.hasClients) {
                            kd = mx;
                            WidgetsBinding.instance.addPostFrameCallback(
                              (_) => kDayCtrl.jumpToItem(kd - 1),
                            );
                          }
                        });
                      },
                      children: List.generate(401, (i) {
                        final y = kYearStart + i;
                        final last = (km == 13)
                            ? (KemeticMath.isLeapKemeticYear(y) ? 6 : 5)
                            : 30;
                        final yStart = KemeticMath.toGregorian(y, km, 1).year;
                        final yEnd = KemeticMath.toGregorian(y, km, last).year;
                        final label = (yStart == yEnd)
                            ? '$yStart'
                            : '$yStart/$yEnd';
                        return Center(
                          child: GlossyText(
                            text: label,
                            style: const TextStyle(fontSize: 14),
                            gradient: silverGloss,
                          ),
                        );
                      }),
                    ),
                  ),
                ],
              ),
            );

            return Padding(
              padding: EdgeInsets.only(
                left: 16,
                right: 16,
                top: 12,
                bottom: MediaQuery.of(sheetCtx).viewInsets.bottom + 12,
              ),
              child: Column(
                mainAxisSize: MainAxisSize.min,
                children: [
                  Container(
                    width: 36,
                    height: 4,
                    margin: const EdgeInsets.only(bottom: 12),
                    decoration: BoxDecoration(
                      color: Colors.white24,
                      borderRadius: BorderRadius.circular(2),
                    ),
                  ),
                  CupertinoSegmentedControl<bool>(
                    groupValue: localKemetic,
                    padding: const EdgeInsets.all(2),
                    children: const {
                      true: Padding(
                        padding: EdgeInsets.symmetric(
                          horizontal: 10,
                          vertical: 6,
                        ),
                        child: Text('Kemetic'),
                      ),
                      false: Padding(
                        padding: EdgeInsets.symmetric(
                          horizontal: 10,
                          vertical: 6,
                        ),
                        child: Text('Gregorian'),
                      ),
                    },
                    onValueChanged: (v) {
                      setSheetState(() {
                        if (v) {
                          final gNow = DateTime(gy, gm, gd);
                          final k = KemeticMath.fromGregorian(gNow);
                          ky = k.kYear;
                          km = k.kMonth;
                          kd = k.kDay;
                          final kMax = kemDayMax(ky, km);
                          if (kd > kMax) kd = kMax;
                          localKemetic = true;

                          WidgetsBinding.instance.addPostFrameCallback((_) {
                            kYearCtrl.jumpToItem(
                              (ky - kYearStart).clamp(0, 400),
                            );
                            kMonthCtrl.jumpToItem((km - 1).clamp(0, 12));
                            kDayCtrl.jumpToItem((kd - 1).clamp(0, 29));
                          });
                        } else {
                          final g = KemeticMath.toGregorian(ky, km, kd);
                          gy = g.year;
                          gm = g.month;
                          gd = g.day;
                          final gMax = gregDayMax(gy, gm);
                          if (gd > gMax) gd = gMax;
                          localKemetic = false;

                          WidgetsBinding.instance.addPostFrameCallback((_) {
                            gYearCtrl.jumpToItem(
                              (gy - gYearStart).clamp(0, 39),
                            );
                            gMonthCtrl.jumpToItem((gm - 1).clamp(0, 11));
                            gDayCtrl.jumpToItem((gd - 1).clamp(0, 30));
                          });
                        }
                      });
                    },
                  ),
                  const SizedBox(height: 10),
                  GlossyText(
                    text: localKemetic
                        ? 'Start date (Kemetic)'
                        : 'Start date (Gregorian)',
                    style: const TextStyle(
                      fontSize: 16,
                      fontWeight: FontWeight.w600,
                    ),
                    gradient: localKemetic ? goldGloss : blueGloss,
                  ),
                  const SizedBox(height: 8),
                  localKemetic ? kemWheel() : gregWheel(),
                  const SizedBox(height: 12),
                  Row(
                    children: [
                      Expanded(
                        child: OutlinedButton(
                          style: OutlinedButton.styleFrom(
                            foregroundColor: Colors.white,
                            side: const BorderSide(color: silver, width: 1.25),
                          ),
                          onPressed: () => Navigator.pop(sheetCtx),
                          child: const Text('Cancel'),
                        ),
                      ),
                      const SizedBox(width: 8),
                      Expanded(
                        child: ElevatedButton(
                          style: ElevatedButton.styleFrom(
                            backgroundColor: localKemetic ? _gold : _blue,
                            foregroundColor: Colors.black,
                          ),
                          onPressed: () {
                            final DateTime chosen = localKemetic
                                ? KemeticMath.toGregorian(ky, km, kd)
                                : DateUtils.dateOnly(DateTime(gy, gm, gd));
                            setState(() {
                              _useKemetic = localKemetic;
                              _picked = chosen;
                            });
                            Navigator.pop(sheetCtx);
                          },
                          child: const Text('Use this date'),
                        ),
                      ),
                    ],
                  ),
                ],
              ),
            );
          },
        );
      },
    );
  }

  void _setTrackSkyPreviewTimeZone(
    TrackSkyTimeZone timezone, {
    bool forceReload = false,
  }) {
    if (!forceReload && _previewTrackSkyTimeZone == timezone) return;
    if (forceReload) {
      clearTrackSkyFlowCache(timezone);
    }
    setState(() {
      _previewTrackSkyTimeZone = timezone;
      _trackSkyFuture = loadTrackSkyFlowData(timezone);
    });
  }

  Future<void> _openTrackSkyJoinSheet() async {
    TrackSkyTimeZone selectedTimeZone = _previewTrackSkyTimeZone;
    int? selectedAlertMinutes;
    bool isWorking = false;

    await showModalBottomSheet<void>(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.black,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(18)),
      ),
      builder: (sheetCtx) {
        final media = MediaQuery.of(sheetCtx);
        return StatefulBuilder(
          builder: (sheetCtx, setSheetState) {
            return AnimatedPadding(
              duration: const Duration(milliseconds: 180),
              curve: Curves.easeOut,
              padding: EdgeInsets.only(bottom: media.viewInsets.bottom),
              child: SafeArea(
                top: false,
                child: FractionallySizedBox(
                  heightFactor: 0.88,
                  child: Padding(
                    padding: EdgeInsets.fromLTRB(
                      16,
                      16,
                      16,
                      16 + media.padding.bottom,
                    ),
                    child: FutureBuilder<TrackSkyFlowData>(
                      future: loadTrackSkyFlowData(selectedTimeZone),
                      builder: (context, snapshot) {
                        final data = snapshot.data;
                        final upcoming = data == null
                            ? const <TrackSkyEvent>[]
                            : upcomingTrackSkyEvents(data);
                        final dateRange = upcoming.isEmpty
                            ? null
                            : '${MaterialLocalizations.of(context).formatShortDate(DateTime.parse(upcoming.first.schedule.dateIso))} → ${MaterialLocalizations.of(context).formatShortDate(DateTime.parse(upcoming.last.schedule.dateIso))}';

                        return Column(
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: [
                            Center(
                              child: Container(
                                width: 36,
                                height: 4,
                                margin: const EdgeInsets.only(bottom: 12),
                                decoration: BoxDecoration(
                                  color: Colors.white24,
                                  borderRadius: BorderRadius.circular(2),
                                ),
                              ),
                            ),
                            Expanded(
                              child: ListView(
                                padding: EdgeInsets.zero,
                                children: [
                                  const GlossyText(
                                    text: 'Join Follow the sky',
                                    gradient: _maatBadgeGoldGloss,
                                    style: TextStyle(
                                      fontSize: 18,
                                      fontWeight: FontWeight.w700,
                                    ),
                                  ),
                                  const SizedBox(height: 8),
                                  Text(
                                    'Choose your timezone and alert preference. The remaining sky events for that timezone will be added to your calendar.',
                                    style: const TextStyle(
                                      color: Colors.white70,
                                      height: 1.35,
                                    ),
                                  ),
                                  const SizedBox(height: 16),
                                  const Text(
                                    'Timezone',
                                    style: TextStyle(
                                      color: Colors.white,
                                      fontWeight: FontWeight.w600,
                                    ),
                                  ),
                                  const SizedBox(height: 8),
                                  ...TrackSkyTimeZone.values.map((timezone) {
                                    return RadioListTile<TrackSkyTimeZone>(
                                      value: timezone,
                                      groupValue: selectedTimeZone,
                                      activeColor: _gold,
                                      contentPadding: EdgeInsets.zero,
                                      title: Text(
                                        timezone.label,
                                        style: const TextStyle(
                                          color: Colors.white,
                                        ),
                                      ),
                                      subtitle: Text(
                                        timezone.shortLabel,
                                        style: const TextStyle(
                                          color: Colors.white54,
                                        ),
                                      ),
                                      onChanged: isWorking
                                          ? null
                                          : (value) {
                                              if (value == null) return;
                                              setSheetState(() {
                                                selectedTimeZone = value;
                                              });
                                            },
                                    );
                                  }),
                                  const SizedBox(height: 8),
                                  const Text(
                                    'Alert',
                                    style: TextStyle(
                                      color: Colors.white,
                                      fontWeight: FontWeight.w600,
                                    ),
                                  ),
                                  const SizedBox(height: 8),
                                  ListTile(
                                    contentPadding: EdgeInsets.zero,
                                    title: const Text(
                                      'Alert preference',
                                      style: TextStyle(color: Colors.white),
                                    ),
                                    subtitle: Text(
                                      selectedAlertMinutes == null
                                          ? 'Choose when you want to be reminded'
                                          : _alertLabelFor(
                                              selectedAlertMinutes,
                                            ),
                                      style: TextStyle(
                                        color: selectedAlertMinutes == null
                                            ? _gold
                                            : Colors.white54,
                                      ),
                                    ),
                                    trailing: const Icon(
                                      Icons.chevron_right,
                                      color: _silver,
                                    ),
                                    onTap: isWorking
                                        ? null
                                        : () async {
                                            final picked =
                                                await _pickAlertMinutes(
                                                  sheetCtx,
                                                  selectedAlertMinutes,
                                                );
                                            if (picked == null) return;
                                            setSheetState(() {
                                              selectedAlertMinutes = picked;
                                            });
                                          },
                                  ),
                                  if (snapshot.hasError) ...[
                                    const SizedBox(height: 8),
                                    const Text(
                                      'Could not load sky events for this timezone.',
                                      style: TextStyle(
                                        color: Colors.white70,
                                        fontSize: 13,
                                      ),
                                    ),
                                    const SizedBox(height: 8),
                                    Align(
                                      alignment: Alignment.centerLeft,
                                      child: OutlinedButton(
                                        style: OutlinedButton.styleFrom(
                                          foregroundColor: _gold,
                                          side: const BorderSide(
                                            color: _gold,
                                            width: 1.1,
                                          ),
                                        ),
                                        onPressed: isWorking
                                            ? null
                                            : () {
                                                clearTrackSkyFlowCache(
                                                  selectedTimeZone,
                                                );
                                                setSheetState(() {});
                                              },
                                        child: const Text('Retry'),
                                      ),
                                    ),
                                  ] else if (snapshot.connectionState ==
                                      ConnectionState.waiting)
                                    const Padding(
                                      padding: EdgeInsets.symmetric(
                                        vertical: 12,
                                      ),
                                      child: Center(
                                        child: CircularProgressIndicator(),
                                      ),
                                    )
                                  else ...[
                                    const SizedBox(height: 8),
                                    Text(
                                      upcoming.isEmpty
                                          ? 'No upcoming sky events remain in this timezone.'
                                          : '${upcoming.length} events will be added${dateRange == null ? '' : ' • $dateRange'}',
                                      style: const TextStyle(
                                        color: Colors.white70,
                                        fontSize: 13,
                                      ),
                                    ),
                                  ],
                                  if (selectedAlertMinutes == null) ...[
                                    const SizedBox(height: 8),
                                    const Text(
                                      'Choose an alert preference before joining.',
                                      style: TextStyle(
                                        color: _gold,
                                        fontSize: 12,
                                      ),
                                    ),
                                  ],
                                ],
                              ),
                            ),
                            const SizedBox(height: 16),
                            SizedBox(
                              width: double.infinity,
                              child: ElevatedButton(
                                style: ElevatedButton.styleFrom(
                                  backgroundColor: _gold,
                                  foregroundColor: Colors.black,
                                  padding: const EdgeInsets.symmetric(
                                    vertical: 14,
                                  ),
                                ),
                                onPressed:
                                    isWorking ||
                                        snapshot.hasError ||
                                        snapshot.connectionState ==
                                            ConnectionState.waiting
                                    ? null
                                    : () async {
                                        if (selectedAlertMinutes == null) {
                                          final picked =
                                              await _pickAlertMinutes(
                                                sheetCtx,
                                                _alertNoneMinutes,
                                              );
                                          if (picked == null) return;
                                          setSheetState(() {
                                            selectedAlertMinutes = picked;
                                          });
                                          return;
                                        }
                                        setSheetState(() => isWorking = true);
                                        final id = await widget.addInstance(
                                          template: widget.template,
                                          trackSkyTimeZone: selectedTimeZone,
                                          alertMinutesBefore:
                                              selectedAlertMinutes!,
                                        );
                                        if (!mounted || !sheetCtx.mounted) {
                                          return;
                                        }
                                        if (id > 0) {
                                          Navigator.of(sheetCtx).pop();
                                          Navigator.of(context).pop(id);
                                        } else {
                                          setSheetState(
                                            () => isWorking = false,
                                          );
                                        }
                                      },
                                child: Text(
                                  isWorking
                                      ? 'Joining…'
                                      : selectedAlertMinutes == null
                                      ? 'Choose Alert'
                                      : 'Join Flow',
                                ),
                              ),
                            ),
                          ],
                        );
                      },
                    ),
                  ),
                ),
              ),
            );
          },
        );
      },
    );
  }

  Widget _buildTrackSkyCategorySection(
    BuildContext context,
    String category,
    List<TrackSkyEvent> events,
  ) {
    if (events.isEmpty) return const SizedBox.shrink();
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        const SizedBox(height: 16),
        GlossyText(
          text: '$category (${events.length})',
          style: const TextStyle(fontSize: 14, fontWeight: FontWeight.w700),
          gradient: silverGloss,
        ),
        const SizedBox(height: 8),
        ...events.map((event) => _buildTrackSkyEventTile(context, event)),
      ],
    );
  }

  Widget _buildTrackSkyEventTile(BuildContext context, TrackSkyEvent event) {
    final detailSummary = event.detailSummary;

    return Container(
      margin: const EdgeInsets.only(bottom: 10),
      decoration: BoxDecoration(
        color: const Color(0xFF0B0C0F),
        borderRadius: BorderRadius.circular(14),
        border: Border.all(color: Colors.white12),
      ),
      child: Theme(
        data: Theme.of(context).copyWith(dividerColor: Colors.transparent),
        child: ExpansionTile(
          tilePadding: const EdgeInsets.symmetric(horizontal: 16, vertical: 4),
          collapsedIconColor: _silver,
          iconColor: _gold,
          childrenPadding: const EdgeInsets.fromLTRB(16, 0, 16, 16),
          title: Text(
            event.title,
            style: const TextStyle(
              color: Colors.white,
              fontWeight: FontWeight.w600,
            ),
          ),
          subtitle: Padding(
            padding: const EdgeInsets.only(top: 4),
            child: Text(
              event.exactLabel,
              style: const TextStyle(color: Colors.white54, fontSize: 12),
            ),
          ),
          children: detailSummary.isEmpty
              ? const <Widget>[]
              : <Widget>[
                  Text(
                    detailSummary,
                    style: const TextStyle(
                      color: Colors.white,
                      fontSize: 13.5,
                      height: 1.45,
                    ),
                  ),
                ],
        ),
      ),
    );
  }

  Widget _buildTrackSkyScaffold(BuildContext context) {
    final media = MediaQuery.of(context);
    final buttonWidth = math.min(media.size.width - 32, 280.0);
    final ctaBottom = media.padding.bottom + 12;
    return Scaffold(
      backgroundColor: _bg,
      appBar: AppBar(
        backgroundColor: Colors.black,
        elevation: 0.5,
        title: GlossyText(
          text: widget.template.title,
          style: const TextStyle(fontSize: 20, fontWeight: FontWeight.w600),
          gradient: goldGloss,
        ),
      ),
      body: Stack(
        children: [
          FutureBuilder<TrackSkyFlowData>(
            future: _trackSkyFuture,
            builder: (context, snapshot) {
              if (snapshot.connectionState == ConnectionState.waiting) {
                return const Center(child: CircularProgressIndicator());
              }
              if (snapshot.hasError) {
                return Center(
                  child: Padding(
                    padding: const EdgeInsets.symmetric(horizontal: 24),
                    child: Column(
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        const Text(
                          'Could not load sky events.',
                          textAlign: TextAlign.center,
                          style: TextStyle(color: Colors.white70),
                        ),
                        const SizedBox(height: 12),
                        OutlinedButton(
                          style: OutlinedButton.styleFrom(
                            foregroundColor: _gold,
                            side: const BorderSide(color: _gold, width: 1.1),
                          ),
                          onPressed: () => _setTrackSkyPreviewTimeZone(
                            _previewTrackSkyTimeZone,
                            forceReload: true,
                          ),
                          child: const Text('Retry'),
                        ),
                      ],
                    ),
                  ),
                );
              }

              final data = snapshot.data;
              if (data == null) {
                return const SizedBox.shrink();
              }
              final upcoming = upcomingTrackSkyEvents(data);
              final l10n = MaterialLocalizations.of(context);
              final firstDate = upcoming.isEmpty
                  ? null
                  : l10n.formatShortDate(
                      DateTime.parse(upcoming.first.schedule.dateIso),
                    );
              final lastDate = upcoming.isEmpty
                  ? null
                  : l10n.formatShortDate(
                      DateTime.parse(upcoming.last.schedule.dateIso),
                    );

              return ListView(
                padding: EdgeInsets.fromLTRB(16, 16, 16, ctaBottom + 96),
                children: [
                  GlossyText(
                    text: widget.template.title,
                    style: const TextStyle(
                      fontSize: 20,
                      fontWeight: FontWeight.w600,
                    ),
                    gradient: goldGloss,
                  ),
                  const SizedBox(height: 8),
                  Text(
                    widget.template.overview,
                    style: const TextStyle(color: Colors.white, height: 1.35),
                  ),
                  const SizedBox(height: 16),
                  const GlossyText(
                    text: 'Preview Timezone',
                    style: TextStyle(fontSize: 14, fontWeight: FontWeight.w700),
                    gradient: silverGloss,
                  ),
                  const SizedBox(height: 8),
                  Wrap(
                    spacing: 8,
                    runSpacing: 8,
                    children: TrackSkyTimeZone.values.map((timezone) {
                      return ChoiceChip(
                        label: Text(timezone.shortLabel),
                        selected: _previewTrackSkyTimeZone == timezone,
                        onSelected: (_) =>
                            _setTrackSkyPreviewTimeZone(timezone),
                        selectedColor: _gold,
                        labelStyle: TextStyle(
                          color: _previewTrackSkyTimeZone == timezone
                              ? Colors.black
                              : Colors.white,
                          fontWeight: FontWeight.w600,
                        ),
                        backgroundColor: const Color(0xFF15171B),
                        side: const BorderSide(color: Colors.white24),
                      );
                    }).toList(),
                  ),
                  const SizedBox(height: 12),
                  Text(
                    upcoming.isEmpty
                        ? 'No upcoming sky events remain in ${_previewTrackSkyTimeZone.label}.'
                        : 'Previewing ${upcoming.length} upcoming events in ${_previewTrackSkyTimeZone.label}${firstDate == null || lastDate == null ? '' : ' • $firstDate → $lastDate'}.',
                    style: const TextStyle(color: Colors.white70, height: 1.35),
                  ),
                  const SizedBox(height: 8),
                  const Text(
                    'Only events with a usable viewing window are included when you join. You can confirm timezone and alert settings from the Join Flow button.',
                    style: TextStyle(
                      color: Colors.white54,
                      fontSize: 12,
                      height: 1.35,
                    ),
                  ),
                  for (final category in kTrackSkyCategoryOrder)
                    _buildTrackSkyCategorySection(
                      context,
                      category,
                      upcoming
                          .where((event) => event.category == category)
                          .toList(),
                    ),
                ],
              );
            },
          ),
          Positioned(
            left: 0,
            right: 0,
            bottom: ctaBottom,
            child: Center(
              child: SizedBox(
                width: buttonWidth,
                child: ElevatedButton(
                  style: ElevatedButton.styleFrom(
                    backgroundColor: const Color(0xFF090A0D),
                    foregroundColor: Colors.white,
                    padding: const EdgeInsets.symmetric(vertical: 15),
                    shape: RoundedRectangleBorder(
                      borderRadius: BorderRadius.circular(999),
                    ),
                    side: const BorderSide(color: _gold, width: 1.15),
                    elevation: 0,
                  ),
                  onPressed: _openTrackSkyJoinSheet,
                  child: const GlossyText(
                    text: 'Join Flow',
                    style: TextStyle(fontSize: 16, fontWeight: FontWeight.w700),
                    gradient: goldGloss,
                  ),
                ),
              ),
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildSequenceScaffold(BuildContext context) {
    final l10n = MaterialLocalizations.of(context);
    return Scaffold(
      backgroundColor: _bg,
      appBar: AppBar(
        backgroundColor: Colors.black,
        elevation: 0.5,
        title: Text(
          widget.template.title,
          style: const TextStyle(color: Colors.white),
        ),
      ),
      body: ListView(
        padding: const EdgeInsets.fromLTRB(16, 16, 16, 24),
        children: [
          GlossyText(
            text: widget.template.title,
            style: const TextStyle(fontSize: 20, fontWeight: FontWeight.w600),
            gradient: goldGloss,
          ),
          const SizedBox(height: 8),
          Text(
            widget.template.overview,
            style: const TextStyle(color: Colors.white, height: 1.35),
          ),
          const SizedBox(height: 16),
          const GlossyText(
            text: '10-Day Outline',
            style: TextStyle(fontSize: 14, fontWeight: FontWeight.w600),
            gradient: silverGloss,
          ),
          const SizedBox(height: 8),
          ...List.generate(widget.template.days.length, (i) {
            final d = widget.template.days[i];
            return Padding(
              padding: const EdgeInsets.only(bottom: 10),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  ...d.notes.asMap().entries.map((entry) {
                    final idx = entry.key;
                    final slot = entry.value;
                    final start = l10n.formatTimeOfDay(slot.start);
                    final end = l10n.formatTimeOfDay(slot.end);
                    return Padding(
                      padding: EdgeInsets.only(
                        bottom: idx == d.notes.length - 1 ? 0 : 6,
                      ),
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: [
                          Text(
                            '$start – $end',
                            style: const TextStyle(
                              color: Colors.white54,
                              fontSize: 12,
                            ),
                          ),
                          const SizedBox(height: 2),
                          Text(
                            slot.title,
                            style: const TextStyle(color: Colors.white),
                          ),
                          if ((slot.detail ?? '').trim().isNotEmpty)
                            Padding(
                              padding: const EdgeInsets.only(top: 4.0),
                              child: Text(
                                slot.detail!.trim(),
                                style: const TextStyle(
                                  color: Colors.white70,
                                  fontSize: 13,
                                  height: 1.35,
                                ),
                              ),
                            ),
                        ],
                      ),
                    );
                  }),
                ],
              ),
            );
          }),
          const SizedBox(height: 12),
          SizedBox(
            width: double.infinity,
            child: OutlinedButton(
              style: OutlinedButton.styleFrom(
                foregroundColor: Colors.white,
                side: const BorderSide(color: silver, width: 1.25),
                alignment: Alignment.centerLeft,
              ),
              onPressed: _pickDate,
              child: Text(
                _picked == null
                    ? 'Pick start date'
                    : (_useKemetic
                          ? 'Start: ${_kemeticLabelFor(_picked!)}'
                          : 'Start: ${_fmtGregorian(_picked!)}'),
              ),
            ),
          ),
          const SizedBox(height: 10),
          if (_picked != null)
            Align(
              alignment: Alignment.centerRight,
              child: Text(
                _useKemetic ? 'Mode: Kemetic' : 'Mode: Gregorian',
                style: const TextStyle(color: Colors.white54, fontSize: 12),
              ),
            ),
          const SizedBox(height: 12),
          ElevatedButton(
            style: ElevatedButton.styleFrom(
              backgroundColor: _gold,
              foregroundColor: Colors.black,
              padding: const EdgeInsets.symmetric(vertical: 14),
            ),
            onPressed: _picked == null
                ? null
                : () async {
                    final id = await widget.addInstance(
                      template: widget.template,
                      startDate: _picked!,
                      useKemetic: _useKemetic,
                    );
                    if (context.mounted) {
                      Navigator.of(context).pop(id);
                    }
                  },
            child: const Text('Add Flow'),
          ),
        ],
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    if (widget.template.kind == _MaatFlowTemplateKind.trackSky) {
      return _buildTrackSkyScaffold(context);
    }
    return _buildSequenceScaffold(context);
  }
}

/* ───────────────────────── Search (notes) ───────────────────────── */

class _EventSearchDelegate extends SearchDelegate<void> {
  _EventSearchDelegate({
    required this.notes,
    required List<_Flow> flows,
    required this.monthName,
    required this.gregYearLabelFor,
    required this.openDay,
  }) : _flowById = {for (final flow in flows) flow.id: flow};

  final Map<String, List<_Note>> notes;
  final Map<int, _Flow> _flowById;
  final String Function(int kMonth) monthName;
  final String Function(int kYear, int kMonth) gregYearLabelFor;
  final void Function(int ky, int km, int kd) openDay;

  @override
  String get searchFieldLabel => 'Search notes…';

  @override
  ThemeData appBarTheme(BuildContext context) {
    final base = Theme.of(context);
    return base.copyWith(
      appBarTheme: const AppBarTheme(color: Colors.black, elevation: 0.5),
      inputDecorationTheme: const InputDecorationTheme(
        hintStyle: TextStyle(color: _silver),
        border: InputBorder.none,
      ),
      textTheme: base.textTheme.apply(
        bodyColor: Colors.white,
        displayColor: Colors.white,
      ),
      scaffoldBackgroundColor: _bg,
      colorScheme: const ColorScheme.dark(
        primary: _gold,
        surface: _bg,
        onSurface: Colors.white,
      ),
    );
  }

  @override
  List<Widget>? buildActions(BuildContext context) => [
    IconButton(
      tooltip: 'Clear',
      onPressed: () => query = '',
      icon: const Icon(Icons.clear),
    ),
  ];

  @override
  Widget? buildLeading(BuildContext context) => IconButton(
    tooltip: 'Back',
    onPressed: () => close(context, null),
    icon: const Icon(Icons.arrow_back),
  );

  Iterable<({int ky, int km, int kd, _Note note})> _matches(String q) sync* {
    if (q.trim().isEmpty) return;
    final qq = q.toLowerCase();
    for (final entry in notes.entries) {
      final parts = entry.key.split('-'); // ky-km-kd
      if (parts.length != 3) continue;
      final ky = int.tryParse(parts[0]) ?? 0;
      final km = int.tryParse(parts[1]) ?? 0;
      final kd = int.tryParse(parts[2]) ?? 0;
      for (final n in entry.value) {
        if (_searchableTextFor(n).contains(qq)) {
          yield (ky: ky, km: km, kd: kd, note: n);
        }
      }
    }
  }

  List<String> _contextFieldsFor(_Note note) {
    final fields = <String>[
      _cleanDetail(note.detail),
      note.location ?? '',
      note.category ?? '',
    ];

    final flowId = note.flowId;
    if (flowId != null && flowId > 0) {
      final flow = _flowById[flowId];
      if (flow != null) {
        final overview = _effectiveOverview(
          flow.notes,
          notesDecode(flow.notes).overview,
        );
        final repeatingMeta = _decodeRepeatingNoteMetadata(flow.notes);
        fields.addAll([
          overview,
          repeatingMeta.detail ?? '',
          repeatingMeta.location ?? '',
          repeatingMeta.category ?? '',
        ]);
      }
    }

    final seen = <String>{};
    final cleaned = <String>[];
    for (final field in fields) {
      final normalized = field.replaceAll(RegExp(r'\s+'), ' ').trim();
      if (normalized.isEmpty) continue;
      if (seen.add(normalized.toLowerCase())) {
        cleaned.add(normalized);
      }
    }
    return cleaned;
  }

  String _searchableTextFor(_Note note) {
    final fields = <String>[note.title, ..._contextFieldsFor(note)];

    final flowId = note.flowId;
    if (flowId != null && flowId > 0) {
      final flow = _flowById[flowId];
      if (flow != null) {
        fields.add(flow.name);
      }
    }

    return fields
        .where((field) => field.trim().isNotEmpty)
        .join('\n')
        .toLowerCase();
  }

  List<String> _queryTerms(String rawQuery) {
    final trimmed = rawQuery.trim().toLowerCase();
    if (trimmed.isEmpty) return const [];

    final seen = <String>{};
    final terms = <String>[];

    void addTerm(String term) {
      final normalized = term.trim().toLowerCase();
      if (normalized.length < 2) return;
      if (seen.add(normalized)) {
        terms.add(normalized);
      }
    }

    for (final term in trimmed.split(RegExp(r'\s+'))) {
      addTerm(term);
    }

    terms.sort((a, b) => b.length.compareTo(a.length));
    return terms;
  }

  String? _contextSnippetFor(_Note note, String rawQuery) {
    final context = _contextFieldsFor(note).join(' ');
    final normalized = context.replaceAll(RegExp(r'\s+'), ' ').trim();
    if (normalized.isEmpty) return null;

    final terms = _queryTerms(rawQuery);
    if (terms.isEmpty) return normalized;
    final matches = _searchHighlightRanges(normalized, terms);

    if (matches.isEmpty) {
      return normalized.length <= 110
          ? normalized
          : '${normalized.substring(0, 107).trimRight()}...';
    }
    final match = matches.first;
    final matchStart = match.start;
    final matchLength = match.end - match.start;

    var start = (matchStart - 32).clamp(0, normalized.length);
    var end = (matchStart + matchLength + 72).clamp(0, normalized.length);

    while (start > 0 && normalized[start] != ' ') {
      start--;
    }
    while (end < normalized.length && normalized[end - 1] != ' ') {
      end++;
      if (end >= normalized.length) {
        end = normalized.length;
        break;
      }
    }

    final snippet = normalized.substring(start, end).trim();
    if (snippet.isEmpty) return null;
    final prefix = start > 0 ? '... ' : '';
    final suffix = end < normalized.length ? ' ...' : '';
    return '$prefix$snippet$suffix';
  }

  Widget _resultsList(String q) {
    final items = _matches(q).toList()
      ..sort((a, b) {
        final ga = KemeticMath.toGregorian(a.ky, a.km, a.kd);
        final gb = KemeticMath.toGregorian(b.ky, b.km, b.kd);
        return ga.compareTo(gb);
      });
    final terms = _queryTerms(q);

    if (items.isEmpty) {
      return const Center(
        child: Padding(
          padding: EdgeInsets.all(24.0),
          child: Text(
            'No matches found',
            style: TextStyle(color: Colors.white70),
          ),
        ),
      );
    }

    return ListView.separated(
      itemCount: items.length,
      separatorBuilder: (_, __) =>
          const Divider(height: 1, color: Colors.white10),
      itemBuilder: (ctx, i) {
        final it = items[i];
        final g = KemeticMath.toGregorian(it.ky, it.km, it.kd);
        final gLabel =
            '${g.year}-${g.month.toString().padLeft(2, '0')}-${g.day.toString().padLeft(2, '0')}';
        final kmLabel = it.km == 13
            ? 'Heriu Renpet (ḥr.w rnpt)'
            : monthName(it.km);

        final subBits = <String>[
          '$kmLabel ${it.kd}',
          gLabel,
          if (it.note.location != null && it.note.location!.isNotEmpty)
            it.note.location!,
        ];
        final subtitle = subBits.join(' • ');
        final snippet = _contextSnippetFor(it.note, q);

        return SizedBox(
          width: double.infinity,
          child: ListTile(
            onTap: () => openDay(it.ky, it.km, it.kd),
            isThreeLine: snippet != null,
            title: Text(
              it.note.title,
              maxLines: 1,
              overflow: TextOverflow.ellipsis,
              style: const TextStyle(color: Colors.white),
            ),
            subtitle: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                if (snippet != null) ...[
                  const SizedBox(height: 4),
                  _SearchSnippetText(snippet: snippet, terms: terms),
                  const SizedBox(height: 4),
                ],
                Text(
                  subtitle,
                  style: const TextStyle(color: Colors.white70, fontSize: 12),
                  maxLines: 1,
                  overflow: TextOverflow.ellipsis,
                ),
              ],
            ),
            trailing: const Icon(Icons.chevron_right, color: _silver),
          ),
        );
      },
    );
  }

  @override
  Widget buildResults(BuildContext context) => _resultsList(query);

  @override
  Widget buildSuggestions(BuildContext context) {
    if (query.trim().isEmpty) {
      return const Center(
        child: Padding(
          padding: EdgeInsets.all(24.0),
          child: Text(
            'Type to search your notes',
            style: TextStyle(color: Colors.white70),
          ),
        ),
      );
    }
    return _resultsList(query);
  }
}

class _SearchSnippetText extends StatelessWidget {
  const _SearchSnippetText({required this.snippet, required this.terms});

  final String snippet;
  final List<String> terms;

  static const _baseStyle = TextStyle(
    color: Colors.white70,
    fontSize: 13,
    height: 1.3,
  );

  @override
  Widget build(BuildContext context) {
    if (terms.isEmpty) {
      return Text(
        snippet,
        style: _baseStyle,
        maxLines: 2,
        overflow: TextOverflow.ellipsis,
      );
    }

    final matches = _searchHighlightRanges(snippet, terms);
    if (matches.isEmpty) {
      return Text(
        snippet,
        style: _baseStyle,
        maxLines: 2,
        overflow: TextOverflow.ellipsis,
      );
    }

    return LayoutBuilder(
      builder: (context, constraints) {
        final boxes = _computeHighlightBoxes(
          snippet,
          matches,
          constraints.maxWidth,
          Directionality.of(context),
        );
        return RichText(
          maxLines: 2,
          overflow: TextOverflow.ellipsis,
          text: TextSpan(children: _buildSnippetSpans(snippet, matches, boxes)),
        );
      },
    );
  }

  List<InlineSpan> _buildSnippetSpans(
    String snippet,
    List<_SearchHighlightRange> matches,
    Map<String, Rect> boxes,
  ) {
    final spans = <InlineSpan>[];
    var cursor = 0;

    for (final match in matches) {
      if (match.start > cursor) {
        spans.add(
          TextSpan(
            text: snippet.substring(cursor, match.start),
            style: _baseStyle,
          ),
        );
      }

      final phrase = snippet.substring(match.start, match.end);
      final box = boxes[_rangeKey(match)];
      final fontSize = _baseStyle.fontSize ?? 13.0;
      final shaderRect = box == null
          ? null
          : Rect.fromLTWH(
              box.left,
              box.top,
              box.width < fontSize ? fontSize : box.width,
              box.height < fontSize * 1.4 ? fontSize * 1.4 : box.height,
            );
      spans.add(
        TextSpan(
          text: phrase,
          style: InsightLinkTextStyle.textSpanStyle(
            _baseStyle.copyWith(
              color: Colors.white,
              fontWeight: FontWeight.w700,
            ),
            phrase,
            shaderRect: shaderRect,
          ),
        ),
      );
      cursor = match.end;
    }

    if (cursor < snippet.length) {
      spans.add(TextSpan(text: snippet.substring(cursor), style: _baseStyle));
    }

    return spans;
  }

  Map<String, Rect> _computeHighlightBoxes(
    String text,
    List<_SearchHighlightRange> matches,
    double maxWidth,
    TextDirection textDirection,
  ) {
    if (!maxWidth.isFinite ||
        maxWidth <= 0 ||
        matches.isEmpty ||
        text.isEmpty) {
      return const {};
    }

    final painter = TextPainter(
      text: TextSpan(text: text, style: _baseStyle),
      textDirection: textDirection,
      maxLines: 2,
      ellipsis: '…',
      textHeightBehavior: const TextHeightBehavior(
        applyHeightToFirstAscent: false,
        applyHeightToLastDescent: false,
      ),
    )..layout(maxWidth: maxWidth);

    final boxes = <String, Rect>{};
    for (final match in matches) {
      final start = match.start.clamp(0, text.length);
      final end = match.end.clamp(start, text.length);
      if (start >= end) continue;

      final textBoxes = painter.getBoxesForSelection(
        TextSelection(baseOffset: start, extentOffset: end),
      );
      if (textBoxes.isEmpty) continue;

      var left = textBoxes.first.left;
      var top = textBoxes.first.top;
      var right = textBoxes.first.right;
      var bottom = textBoxes.first.bottom;

      for (final textBox in textBoxes.skip(1)) {
        if (textBox.left < left) left = textBox.left;
        if (textBox.top < top) top = textBox.top;
        if (textBox.right > right) right = textBox.right;
        if (textBox.bottom > bottom) bottom = textBox.bottom;
      }

      boxes[_rangeKey(match)] = Rect.fromLTRB(left, top, right, bottom);
    }

    return boxes;
  }

  String _rangeKey(_SearchHighlightRange range) =>
      '${range.start}:${range.end}';
}

class _SearchHighlightRange {
  const _SearchHighlightRange(this.start, this.end);

  final int start;
  final int end;
}

final RegExp _searchWordChar = RegExp(r'[A-Za-z0-9\u00C0-\u024F\u1E00-\u1EFF]');

List<_SearchHighlightRange> _searchHighlightRanges(
  String text,
  List<String> terms,
) {
  if (text.isEmpty || terms.isEmpty) return const [];

  final lower = text.toLowerCase();
  final candidates = <_SearchHighlightRange>[];

  for (final term in terms) {
    if (term.isEmpty) continue;
    var searchFrom = 0;
    while (searchFrom < lower.length) {
      final start = lower.indexOf(term, searchFrom);
      if (start == -1) break;
      final end = start + term.length;
      if (_isValidSearchMatch(text, term, start, end)) {
        candidates.add(_SearchHighlightRange(start, end));
      }
      searchFrom = start + 1;
    }
  }

  candidates.sort((a, b) {
    final byStart = a.start.compareTo(b.start);
    if (byStart != 0) return byStart;
    return (b.end - b.start).compareTo(a.end - a.start);
  });

  final accepted = <_SearchHighlightRange>[];
  for (final candidate in candidates) {
    if (accepted.isEmpty || candidate.start >= accepted.last.end) {
      accepted.add(candidate);
    }
  }
  return accepted;
}

bool _isValidSearchMatch(String text, String term, int start, int end) {
  final needsLeadingBoundary = _isSearchWordChar(term[0]);
  final needsTrailingBoundary = _isSearchWordChar(term[term.length - 1]);

  if (needsLeadingBoundary && start > 0 && _isSearchWordChar(text[start - 1])) {
    return false;
  }
  if (needsTrailingBoundary &&
      end < text.length &&
      _isSearchWordChar(text[end])) {
    return false;
  }
  return true;
}

bool _isSearchWordChar(String char) => _searchWordChar.hasMatch(char);

/* ───────────────────────── Simple Note model ───────────────────────── */

class _Note {
  final String? id; // optional persistent id
  final String? clientEventId;
  final String title;
  final String? detail;
  final String? location;
  final bool allDay;
  final TimeOfDay? start;
  final TimeOfDay? end;

  /// which flow created this note (for Ma'at flow cleanup). null for normal notes.
  final int? flowId;

  /// Manual color for notes that aren't driven by a flow.
  final Color? manualColor;
  final String? category; // optional category label
  final bool isReminder;
  final String? reminderId;
  final int?
  alertOffsetMinutes; // minutes before start; -1 = none, null = default

  const _Note({
    this.id,
    this.clientEventId,
    required this.title,
    this.detail,
    this.location,
    required this.allDay,
    this.start,
    this.end,
    this.flowId,
    this.manualColor,
    this.category,
    this.isReminder = false,
    this.reminderId,
    this.alertOffsetMinutes,
  });

  _Note copyWith({
    String? id,
    String? clientEventId,
    String? title,
    String? detail,
    String? location,
    bool? allDay,
    TimeOfDay? start,
    TimeOfDay? end,
    int? flowId,
    Color? manualColor,
    String? category,
    bool? isReminder,
    String? reminderId,
    int? alertOffsetMinutes,
  }) {
    return _Note(
      id: id ?? this.id,
      clientEventId: clientEventId ?? this.clientEventId,
      title: title ?? this.title,
      detail: detail ?? this.detail,
      location: location ?? this.location,
      allDay: allDay ?? this.allDay,
      start: start ?? this.start,
      end: end ?? this.end,
      flowId: flowId ?? this.flowId,
      manualColor: manualColor ?? this.manualColor,
      category: category ?? this.category,
      isReminder: isReminder ?? this.isReminder,
      reminderId: reminderId ?? this.reminderId,
      alertOffsetMinutes: alertOffsetMinutes ?? this.alertOffsetMinutes,
    );
  }
}

// ========================================
// CUSTOM REPEAT PAGE
// ========================================

class _CustomRepeatPage extends StatefulWidget {
  final SimpleRecurrenceFrequency initialFrequency;
  final int initialInterval;

  const _CustomRepeatPage({
    Key? key,
    required this.initialFrequency,
    required this.initialInterval,
  }) : super(key: key);

  @override
  State<_CustomRepeatPage> createState() => _CustomRepeatPageState();
}

class _CustomRepeatPageState extends State<_CustomRepeatPage> {
  late SimpleRecurrenceFrequency _freq;
  late int _interval;

  @override
  void initState() {
    super.initState();
    _freq = widget.initialFrequency;
    _interval = widget.initialInterval.clamp(1, 999);
  }

  String _freqLabel(SimpleRecurrenceFrequency f) {
    switch (f) {
      case SimpleRecurrenceFrequency.daily:
        return 'Daily';
      case SimpleRecurrenceFrequency.weekly:
        return 'Weekly';
      case SimpleRecurrenceFrequency.monthly:
        return 'Monthly';
      case SimpleRecurrenceFrequency.yearly:
        return 'Yearly';
    }
  }

  String _unitLabel() {
    switch (_freq) {
      case SimpleRecurrenceFrequency.daily:
        return _interval == 1 ? 'day' : 'days';
      case SimpleRecurrenceFrequency.weekly:
        return _interval == 1 ? 'week' : 'weeks';
      case SimpleRecurrenceFrequency.monthly:
        return _interval == 1 ? 'month' : 'months';
      case SimpleRecurrenceFrequency.yearly:
        return _interval == 1 ? 'year' : 'years';
    }
  }

  Widget _divider() => Container(
    height: 1,
    color: Colors.white12,
    margin: const EdgeInsets.symmetric(horizontal: 16),
  );

  Widget _row({
    required String label,
    required Widget trailing,
    VoidCallback? onTap,
  }) {
    return InkWell(
      onTap: onTap,
      child: Container(
        padding: const EdgeInsets.symmetric(vertical: 20, horizontal: 20),
        child: Row(
          mainAxisAlignment: MainAxisAlignment.spaceBetween,
          children: [
            GlossyText(
              text: label,
              gradient: goldGloss,
              style: const TextStyle(
                fontSize: 16,
                fontWeight: FontWeight.w600,
                decoration: TextDecoration.none,
              ),
            ),
            trailing,
          ],
        ),
      ),
    );
  }

  Future<void> _showFrequencySheet() async {
    final result = await showCupertinoModalPopup<SimpleRecurrenceFrequency>(
      context: context,
      builder: (_) {
        return CupertinoActionSheet(
          title: const GlossyText(
            text: 'Frequency',
            gradient: silverGloss,
            style: TextStyle(fontSize: 18),
          ),
          actions: [
            for (final f in SimpleRecurrenceFrequency.values)
              CupertinoActionSheetAction(
                onPressed: () {
                  Navigator.pop(context, f);
                },
                child: GlossyText(
                  text: _freqLabel(f),
                  gradient: goldGloss,
                  style: const TextStyle(fontSize: 17),
                ),
              ),
          ],
          cancelButton: CupertinoActionSheetAction(
            isDestructiveAction: true,
            onPressed: () => Navigator.pop(context),
            child: const Text('Cancel'),
          ),
        );
      },
    );

    if (result != null) {
      setState(() => _freq = result);
    }
  }

  @override
  Widget build(BuildContext context) {
    return CupertinoPageScaffold(
      backgroundColor: Colors.black,
      navigationBar: CupertinoNavigationBar(
        backgroundColor: Colors.black,
        border: null,
        previousPageTitle: 'Repeat',
        middle: const GlossyText(
          text: 'Custom',
          gradient: silverGloss,
          style: TextStyle(fontSize: 18),
        ),
        trailing: CupertinoButton(
          padding: useExpandedTouchTargets(context)
              ? const EdgeInsets.symmetric(horizontal: 12, vertical: 8)
              : EdgeInsets.zero,
          onPressed: () {
            Navigator.pop<Map<String, dynamic>>(context, {
              'frequency': _freq,
              'interval': _interval,
            });
          },
          child: GlossyText(
            text: 'Done',
            gradient: goldGloss,
            style: const TextStyle(fontSize: 16, fontWeight: FontWeight.w700),
          ),
        ),
      ),
      child: SafeArea(
        bottom: false,
        child: Column(
          children: [
            const SizedBox(height: 20),

            // MAIN CARD
            Padding(
              padding: const EdgeInsets.symmetric(horizontal: 16),
              child: Container(
                decoration: BoxDecoration(
                  color: const Color(0xFF1C1C1E),
                  borderRadius: BorderRadius.circular(16),
                  border: Border.all(color: Colors.white12, width: 1),
                ),
                child: Column(
                  children: [
                    _row(
                      label: 'Frequency',
                      trailing: Row(
                        children: [
                          GlossyText(
                            text: _freqLabel(_freq),
                            gradient: silverGloss,
                            style: const TextStyle(
                              fontSize: 16,
                              fontWeight: FontWeight.w600,
                              decoration: TextDecoration.none,
                            ),
                          ),
                          const SizedBox(width: 4),
                          const Icon(
                            Icons.keyboard_arrow_down,
                            color: Colors.white54,
                          ),
                        ],
                      ),
                      onTap: _showFrequencySheet,
                    ),

                    _divider(),

                    _row(
                      label: 'Every',
                      trailing: GlossyText(
                        text: _unitLabel().capitalizeFirst(),
                        gradient: goldGloss,
                        style: const TextStyle(
                          fontSize: 16,
                          fontWeight: FontWeight.w600,
                          decoration: TextDecoration.none,
                        ),
                      ),
                    ),

                    _divider(),

                    // INTERVAL PICKER
                    SizedBox(
                      height: 160,
                      child: CupertinoPicker(
                        itemExtent: 34,
                        scrollController: FixedExtentScrollController(
                          initialItem: (_interval - 1).clamp(0, 998),
                        ),
                        onSelectedItemChanged: (index) {
                          setState(() {
                            _interval = index + 1;
                          });
                        },
                        backgroundColor: Colors.black,
                        children: List.generate(999, (i) {
                          final v = i + 1;
                          return Center(
                            child: GlossyText(
                              text: '$v',
                              gradient: silverGloss,
                              style: const TextStyle(
                                fontSize: 18,
                                fontWeight: FontWeight.w600,
                                decoration: TextDecoration.none,
                              ),
                            ),
                          );
                        }),
                      ),
                    ),
                  ],
                ),
              ),
            ),

            const SizedBox(height: 20),

            // SUMMARY
            Padding(
              padding: const EdgeInsets.symmetric(horizontal: 20),
              child: GlossyText(
                text: 'Event will occur every $_interval ${_unitLabel()}.',
                gradient: silverGloss,
                style: const TextStyle(
                  fontSize: 14,
                  fontWeight: FontWeight.w500,
                  decoration: TextDecoration.none,
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }
}

// Helper extension for capitalizeFirst
extension _CapitalizeFirst on String {
  String capitalizeFirst() =>
      isEmpty ? this : this[0].toUpperCase() + substring(1);
}

// ========================================
// GOLD DIVIDER WIDGET
// ========================================

class _GoldDivider extends StatelessWidget {
  const _GoldDivider();

  @override
  Widget build(BuildContext context) {
    final w = (MediaQuery.of(context).size.width * 0.82)
        .floorToDouble(); // snap to px
    return Padding(
      padding: const EdgeInsets.symmetric(vertical: 16), // 16px above and below
      child: Center(
        child: RepaintBoundary(
          child: ShaderMask(
            shaderCallback: (Rect r) =>
                goldGloss.createShader(r), // same gradient as titles
            blendMode: BlendMode.srcIn,
            child: SizedBox(
              width: w,
              height: 1.0,
              child: const DecoratedBox(
                decoration: BoxDecoration(
                  color: Color(0xFFFFFFFF),
                ), // white base for mask
              ),
            ),
          ),
        ),
      ),
    );
  }
}

String _reminderRepeatLabelForPicker(ReminderRepeatKind kind) {
  switch (kind) {
    case ReminderRepeatKind.none:
      return 'Never';
    case ReminderRepeatKind.everyNDays:
      return 'Every X days';
    case ReminderRepeatKind.weekly:
      return 'Weekly on…';
    case ReminderRepeatKind.monthlyDay:
      return 'Monthly on date';
    case ReminderRepeatKind.kemeticEveryNDecans:
      return 'Every X decans';
    case ReminderRepeatKind.kemeticDecanDay:
      return 'Same day each decan';
    case ReminderRepeatKind.kemeticMonthDay:
      return 'Same date each Kemetic month';
  }
}
